// --- IMPROVED AUDIO ENGINE ---
const audioCtxRef: { current: AudioContext | null } = { current: null };

const playFeedbackSound = (type: 'correct' | 'wrong' | 'complete') => {
    if (typeof window === 'undefined') return;

    if (!audioCtxRef.current) {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContext) {
            audioCtxRef.current = new AudioContext();
        }
    }

    const ctx = audioCtxRef.current;
    if (!ctx) return;

    if (ctx.state === 'suspended') {
        ctx.resume().catch(() => {});
    }

    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'correct') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now); 
        osc.frequency.exponentialRampToValueAtTime(50, now + 0.5); 
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
        osc.start(now);
        osc.stop(now + 0.5);
    } 
    else if (type === 'wrong') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(150, now);
        osc.frequency.linearRampToValueAtTime(100, now + 0.15);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
    } 
    else if (type === 'complete') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.setValueAtTime(554, now + 0.1);
        osc.frequency.setValueAtTime(659, now + 0.2);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.6);
        osc.start(now);
        osc.stop(now + 0.6);
    }
};

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=800&q=75&output=webp&il`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => {
  return text.replace(/^(Option|Part)\s+/i, '').trim();
};

const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader, isEmbedded = false, enableConfiguration = false, onExit }) => {
  const savedState = useMemo(() => {
    if (isEmbedded) return null;
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, [isEmbedded]);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(
    savedState?.view || (isEmbedded && !enableConfiguration ? 'playing' : 'setup')
  );

  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);
  const [streak, setStreak] = useState(0);

  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(
    (isEmbedded && !enableConfiguration) ? 'practice' : (savedState?.mode || 'exam')
  );

  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(!isEmbedded); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Helper to prepare questions
  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length > 0 ? [...q.options] : [q.answerText];
      if (finalOptions.length < 2) {
         finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not shown"];
      }
      finalOptions.sort(() => Math.random() - 0.5);
      return {
        id: q.id, 
        data: q,
        options: finalOptions,
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  // Embedded Initialization
  useEffect(() => {
    // Only auto-start if we are embedded AND configuration is NOT enabled.
    // If configuration IS enabled, we let the user pick in the Setup view.
    if (isEmbedded && !enableConfiguration && questions.length === 0 && data.length > 0) {
        let pool = [...data];
        // Shuffle for embedded practice
        pool.sort(() => Math.random() - 0.5);
        const prepared = prepareQuestions(pool);
        setQuestions(prepared);
        setTimeLeft(prepared.length * 60);
        setView('playing');
        setMode('practice');
        if (toggleHeader) toggleHeader(false);
    } else if (isEmbedded && enableConfiguration && questions.length === 0 && data.length > 0) {
        // Just ensure header is hidden if needed, but stay in setup
        if (toggleHeader) toggleHeader(false);
    }
  }, [isEmbedded, enableConfiguration, data, questions.length, toggleHeader]);

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (!isEmbedded) {
        if (view === 'playing' || view === 'results' || view === 'review') {
        localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({
            view, questions, currentQIndex, timeLeft, mode
        }));
        } else {
        localStorage.removeItem('OT_QUIZ_SESSION_V5');
        }
    }
  }, [view, questions, currentQIndex, timeLeft, mode, isEmbedded]);

  useEffect(() => {
    if (!isEmbedded && toggleHeader) {
        if (view === 'playing' || view === 'review') {
            toggleHeader(false);
        } else {
            toggleHeader(true);
        }
    }
  }, [view, toggleHeader, isEmbedded]);

  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024 || isEmbedded) {
            setIsSidebarOpen(false);
        } else {
            setIsSidebarOpen(true);
        }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, [isEmbedded]);

  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    if (questionRef.current) {
        questionRef.current.scrollTop = 0;
    }
  }, [currentQIndex, view]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (view !== 'playing') return;
      if (e.key === 'ArrowLeft') {
        if (currentQIndex > 0) {
            e.preventDefault();
            setCurrentQIndex(prev => prev - 1);
            setImgError(false);
        }
      } else if (e.key === 'ArrowRight') {
        if (currentQIndex < questions.length - 1) {
            e.preventDefault();
            setCurrentQIndex(prev => prev + 1);
            setImgError(false);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [view, currentQIndex, questions.length]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const startSession = () => {
    let pool = data;
    if (mode === 'mistakes') pool = pool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) pool = pool.filter(q => q.questionImage || q.answerImage);

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    if (isShuffle) pool = [...pool].sort(() => Math.random() - 0.5);

    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);
    const preparedQuestions = prepareQuestions(finalPool);

    if (typeof window !== 'undefined' && (window.AudioContext || (window as any).webkitAudioContext)) {
        if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioCtxRef.current.resume();
    }

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    if(toggleHeader) toggleHeader(false);
  };

  const handleFinish = () => {
    cancel();
    playFeedbackSound('complete');
    setView('results');
  };

  const saveAndExit = (resolveCorrect: boolean) => {
    const wrongIds = questions.filter(q => q.userAnswer !== q.correctOption).map(q => q.id);
    const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
        let next = [...prev];
        if (wrongIds.length > 0) next = [...next, ...wrongIds];
        if (resolveCorrect) next = next.filter(id => !correctIds.includes(id));
        return Array.from(new Set(next));
    });

    if (isEmbedded && onExit) {
        onExit();
    } else {
        localStorage.removeItem('OT_QUIZ_SESSION_V5');
        setView('setup');
        if(toggleHeader) toggleHeader(true);
    }
  };

  const retrySession = () => {
    const resetQuestions = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
    const reshuffled = [...resetQuestions].sort(() => Math.random() - 0.5);
    setQuestions(reshuffled);
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(reshuffled.length * 60);
    setView('playing');
    if(toggleHeader) toggleHeader(false);
  };

  const retryIncorrectOnly = () => {
    const wrongQuestions = questions
        .filter(q => q.userAnswer !== q.correctOption)
        .map(q => ({...q, userAnswer: null, isFlagged: false}));

    if (wrongQuestions.length === 0) return;

    setQuestions(wrongQuestions.sort(() => Math.random() - 0.5));
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(wrongQuestions.length * 60);
    setView('playing');
    if(toggleHeader) toggleHeader(false);
  };

  const exitQuiz = () => {
    if (confirm("End current exam session? Progress will be lost.")) {
      cancel();
      if (isEmbedded && onExit) {
          onExit();
      } else {
          localStorage.removeItem('OT_QUIZ_SESSION_V5');
          setView('setup');
          if(toggleHeader) toggleHeader(true);
      }
    }
  };

  const filterOptions: FilterOption[] = [
    { label: 'Diagrams Only', subLabel: 'Visual Mode', icon: ImageIcon, isActive: showDiagramsOnly, onClick: () => setShowDiagramsOnly(!showDiagramsOnly), colorTheme: 'indigo' }
  ];

  // --- VIEW: SETUP ---
  if (view === 'setup') {
    let filteredPool = data;
    if (mode === 'mistakes') filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    const maxQuestions = filteredPool.length;
    if (questionCount > maxQuestions && maxQuestions > 0) setQuestionCount(maxQuestions);

    return (
      <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar relative">
          <div className="min-h-full flex flex-col items-center justify-center p-4 pb-32 md:pb-10">
             <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-200/50 overflow-hidden animate-in zoom-in-95 duration-500 relative">
                {isEmbedded && (
                    <button onClick={onExit} className="absolute top-4 right-4 text-white hover:bg-white/10 p-2 rounded-full z-20"><X size={20}/></button>
                )}
                <div className="bg-slate-900 p-8 md:p-10 text-white relative overflow-hidden">
                    <div className="absolute top-[-20%] right-[-10%] opacity-10"><Monitor size={200} /></div>
                    <h2 className="text-2xl md:text-3xl font-display font-bold tracking-tight mb-2">Exam Configuration</h2>
                    <p className="text-slate-400 text-sm font-medium">Occupational Therapy Department</p>
                </div>
                <div className="p-6 md:p-10 space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {[
                        { id: 'exam', label: 'University Exam', sub: 'Timed • No Hints', icon: Clock, color: 'rose' },
                        { id: 'practice', label: 'Study Mode', sub: 'Interactive Feedback', icon: Zap, color: 'blue' },
                        { id: 'mistakes', label: 'Error Vault', sub: `${mistakesVault.length} items`, icon: AlertTriangle, color: 'amber' }
                    ].map((m) => (
                        <button key={m.id} onClick={() => setMode(m.id as any)} className={`p-5 rounded-2xl border-2 transition-all text-left flex flex-col gap-3 group relative overflow-hidden ${mode === m.id ? `border-${m.color}-500 bg-${m.color}-50 text-${m.color}-900` : 'border-slate-100 hover:border-slate-300 text-slate-500 hover:bg-slate-50'}`}>
                            <div className={`p-2.5 rounded-xl w-fit ${mode === m.id ? `bg-${m.color}-200 text-${m.color}-700` : 'bg-slate-100 group-hover:bg-slate-200'}`}><m.icon size={20} /></div>
                            <div><span className="block font-bold text-sm">{m.label}</span><span className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{m.sub}</span></div>
                        </button>
                    ))}
                    </div>
                    <div className="space-y-6 border-t border-slate-100 pt-6">
                        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                            {/* Hide Category Selector if embedded, because the content is fixed to the Atlas image context */}
                            {!isEmbedded && (
                                <button onClick={() => setIsBankModalOpen(true)} className={`flex-1 w-full p-4 rounded-xl border-2 flex items-center justify-between transition-all ${selectedCategories.length > 0 ? 'border-slate-800 bg-slate-800 text-white' : 'border-slate-200 hover:border-slate-300 text-slate-600 hover:bg-slate-50'}`}>
                                    <div className="flex items-center gap-3"><List size={18} /><div className="text-left"><span className="block text-[10px] font-black uppercase tracking-widest opacity-70">Content Source</span><span className="block text-sm font-bold truncate max-w-[200px]">{selectedCategories.length === 0 ? "All Chapters (Comprehensive)" : `${selectedCategories.length} Modules Selected`}</span></div></div><ChevronRight size={16} />
                                </button>
                            )}
                            <div className="flex-1 w-full space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-widest px-1"><span>Question Limit</span><span className="text-slate-900">{questionCount} / {maxQuestions}</span></div>
                                <input type="range" min="1" max={maxQuestions || 1} value={questionCount} disabled={maxQuestions === 0} onChange={(e) => setQuestionCount(Number(e.target.value))} className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900"/>
                            </div>
                        </div>
                    </div>
                    <button onClick={startSession} disabled={maxQuestions === 0} className="w-full py-5 bg-slate-900 hover:bg-rose-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl hover:shadow-2xl transition-all hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"><span>Start Examination</span><ChevronRight size={18} /></button>
                </div>
             </div>
          </div>
          <FilterModal isOpen={isBankModalOpen} onClose={() => setIsBankModalOpen(false)} categories={categories} selectedCategories={selectedCategories} onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} onClearAll={() => { setSelectedCategories([]); setShowDiagramsOnly(false); }} mainOptions={filterOptions} title="Curriculum Selection" />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing' && currentQ) {
    return (
      <div className={`h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900 ${isEmbedded ? 'rounded-none' : ''}`}>

        {/* Top Information Bar */}
        <header className="h-14 md:h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-white text-rose-600 border border-rose-100 rounded-lg flex items-center justify-center shadow-sm">
                    <HeartPulse size={18} className="text-rose-600 md:w-5 md:h-5" />
                </div>
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Anatomy & Physiology</h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{isPracticeMode ? 'Formative Assessment' : 'Summative Exam'}</p>
                </div>
                <div className="md:hidden">
                    <span className="text-xs font-bold text-slate-900">Q{currentQIndex + 1}/{questions.length}</span>
                </div>
            </div>

            <div className="flex items-center gap-3 md:gap-6">
                {mode === 'exam' ? (
                    <div className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-4 py-1.5 md:py-2 rounded-lg font-mono font-bold text-sm md:text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-50 text-slate-700 border-slate-200'}`}>
                        <Clock size={16} className="md:w-[18px] md:h-[18px]" /> {formatTime(timeLeft)}
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <span className="px-2 md:px-3 py-1 md:py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-lg text-[10px] md:text-xs font-bold flex items-center gap-1"><CheckCircle2 size={12} className="md:w-3.5 md:h-3.5" /> {questions.filter(q => q.userAnswer === q.correctOption).length}</span>
                        <span className="px-2 md:px-3 py-1 md:py-1.5 bg-rose-50 text-rose-700 border border-rose-200 rounded-lg text-[10px] md:text-xs font-bold flex items-center gap-1"><X size={12} className="md:w-3.5 md:h-3.5" /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</span>
                    </div>
                )}

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors lg:hidden shadow-sm">
                    <LayoutGrid size={18} className="text-slate-600" />
                </button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden relative">

            {/* Main Question Paper */}
            <main className="flex-1 flex flex-col relative min-w-0">
                {/* Progress Strip */}
                <div className="h-1 bg-slate-200 w-full">
                    <div 
                        className="h-full bg-rose-500 transition-all duration-300" 
                        style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                    />
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white min-h-[500px] shadow-sm border border-slate-200 rounded-2xl overflow-hidden pb-8">

                        {/* Question Header */}
                        <div className="bg-slate-50/80 border-b border-slate-100 p-4 md:p-6 flex justify-between items-start">
                            <div className="flex flex-col gap-1.5 pr-4">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest hidden md:block">Question {currentQIndex + 1} of {questions.length}</span>
                                <span className="text-[10px] md:text-xs font-bold text-slate-600 bg-white border border-slate-200 px-3 py-1 rounded-md w-fit max-w-[200px] md:max-w-full truncate">{currentQ.data.category}</span>
                            </div>
                            <div className="flex gap-2 shrink-0">
                                <button onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged; return c; })} className={`p-2 md:p-2.5 rounded-lg border transition-all ${currentQ.isFlagged ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`} title="Mark for Review"><Flag size={16} className="md:w-[18px] md:h-[18px]" fill={currentQ.isFlagged ? "currentColor" : "none"} /></button>
                                <button onClick={() => speak(currentQ.data.questionText, currentQ.id)} className={`p-2 md:p-2.5 rounded-lg border transition-all ${isSpeaking && speakingId === currentQ.id ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}>{isSpeaking && speakingId === currentQ.id ? <VolumeX size={16} className="md:w-[18px] md:h-[18px]" /> : <Volume2 size={16} className="md:w-[18px] md:h-[18px]" />}</button>
                            </div>
                        </div>

                        <div className="p-4 md:p-12 space-y-6 md:space-y-8">
                            {/* Stem */}
                            <h2 className="text-lg md:text-2xl font-display font-medium text-slate-900 leading-relaxed text-balance">
                                <span dangerouslySetInnerHTML={{ __html: formatQuestionText(currentQ.data.questionText) }} />
                            </h2>

                            {/* Image */}
                            {currentQ.data.questionImage && !imgError && (
                                <div className="border border-slate-100 rounded-xl p-2 md:p-4 bg-slate-50 flex justify-center">
                                    <img src={cleanImageUrl(currentQ.data.questionImage)} alt="Clinical Figure" className="max-h-[30vh] md:max-h-[40vh] w-auto object-contain rounded-lg shadow-sm" onError={() => setImgError(true)} />
                                </div>
                            )}

                            {/* Options */}
                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const isCorrect = isPracticeMode && currentQ.userAnswer && opt === currentQ.correctOption;
                                    const isWrong = isPracticeMode && currentQ.userAnswer && isSelected && opt !== currentQ.correctOption;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;

                                    let containerStyle = "border-slate-200 hover:border-slate-300 hover:bg-slate-50 cursor-pointer";
                                    let circleStyle = "border-slate-300 text-slate-500 bg-white";

                                    if (showAnswer) {
                                        if (isCorrect) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/50 cursor-default ring-1 ring-emerald-500 animate-in pulse";
                                            circleStyle = "bg-emerald-500 border-emerald-500 text-white";
                                        } else if (isWrong) {
                                            containerStyle = "border-rose-500 bg-rose-50/50 cursor-default ring-1 ring-rose-500 animate-in shake";
                                            circleStyle = "bg-rose-500 border-rose-500 text-white";
                                        } else if (opt === currentQ.correctOption) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/20 cursor-default"; 
                                            circleStyle = "border-emerald-500 text-emerald-600 bg-emerald-50";
                                        } else {
                                            containerStyle = "border-slate-100 text-slate-400 cursor-default opacity-60";
                                        }
                                    } else if (isSelected) {
                                        containerStyle = "border-slate-900 bg-slate-50 shadow-md ring-1 ring-slate-900";
                                        circleStyle = "bg-slate-900 border-slate-900 text-white";
                                    }

                                    return (
                                        <div key={i} onClick={() => {
                                            if (showAnswer) return;
                                            const correct = opt === currentQ.correctOption;
                                            if (isPracticeMode) {
                                                if (correct) { playFeedbackSound('correct'); setStreak(s => s + 1); } 
                                                else { playFeedbackSound('wrong'); setStreak(0); }
                                            }
                                            setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; });
                                        }} className={`group relative flex items-center gap-3 md:gap-4 p-3 md:p-4 rounded-xl border-2 transition-all duration-200 ${containerStyle}`}>
                                            <div className={`w-7 h-7 md:w-8 md:h-8 rounded-lg border-2 flex items-center justify-center text-xs md:text-sm font-bold shrink-0 transition-colors ${circleStyle}`}>
                                                {showAnswer && isCorrect ? <Check size={14} className="md:w-4 md:h-4" /> : showAnswer && isWrong ? <X size={14} className="md:w-4 md:h-4" /> : letter}
                                            </div>
                                            <div className="flex-1 text-sm md:text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-4 md:p-6 rounded-xl border text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 shadow-sm relative ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-slate-50 border-slate-200 text-slate-800'}`}>
                                    <div className="flex justify-between items-start mb-2">
                                        <h4 className="font-bold uppercase tracking-widest text-xs opacity-70 flex items-center gap-2">
                                            {currentQ.userAnswer === currentQ.correctOption ? <CheckCircle2 size={16} /> : <AlertTriangle size={16} />}
                                            {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                        </h4>
                                        <button onClick={() => speak(currentQ.data.explanation || "No additional clinical notes available.", currentQ.id + '-expl')} className={`p-1.5 rounded-lg border transition-all ${isSpeaking && speakingId === currentQ.id + '-expl' ? 'bg-white border-current text-current' : 'bg-transparent border-transparent hover:bg-white/50'}`} title="Read Explanation">{isSpeaking && speakingId === currentQ.id + '-expl' ? <VolumeX size={14} /> : <Volume2 size={14} />}</button>
                                    </div>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No additional clinical notes available." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Controls */}
                <div className="bg-white border-t border-slate-200 p-4 md:px-8 flex justify-between items-center shadow-[0_-4px_20px_-5px_rgba(0,0,0,0.05)] z-20">
                    <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="flex items-center gap-2 px-4 md:px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest text-slate-600 hover:bg-slate-50 disabled:opacity-30 disabled:hover:bg-transparent transition-all"><ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span></button>
                    <button onClick={() => { if (currentQIndex === questions.length - 1) { handleFinish(); } else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} className="flex items-center gap-2 px-6 md:px-8 py-3 rounded-xl font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg shadow-slate-200 hover:shadow-rose-100 transition-all hover:-translate-y-0.5 active:translate-y-0">{currentQIndex === questions.length - 1 ? 'Submit Exam' : 'Next'} {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}</button>
                </div>
            </main>

            {/* Sidebar Overlay (Mobile) & Fixed Sidebar (Desktop) */}
            <>
                {/* Backdrop for mobile */}
                {isSidebarOpen && (
                    <div 
                        className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-40 lg:hidden animate-in fade-in"
                        onClick={() => setIsSidebarOpen(false)}
                    />
                )}

                <aside className={`fixed inset-y-0 right-0 z-50 w-[85vw] md:w-80 bg-white shadow-2xl transform transition-transform duration-300 lg:relative lg:translate-x-0 lg:shadow-none lg:z-auto lg:border-l lg:border-slate-200 flex flex-col ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                    <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50/50">
                        <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 p-2 hover:bg-slate-200 rounded-full"><X size={20} /></button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 custom-scrollbar bg-slate-50/30">
                        <div className="grid grid-cols-5 gap-2.5">
                            {questions.map((q, i) => {
                                let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-300 shadow-sm";
                                if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200 shadow-md transform scale-105 z-10";
                                else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-700";
                                else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";
                                return (<button key={i} onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} className={`aspect-square rounded-lg flex items-center justify-center text-xs font-medium border-2 transition-all relative group ${style}`}>{i + 1}{q.isFlagged && <div className="absolute top-0.5 right-0.5 w-2 h-2 bg-amber-500 rounded-full border border-white"></div>}</button>)
                            })}
                        </div>
                    </div>

                    <div className="p-6 border-t border-slate-200 bg-white space-y-4 pb-safe">
                        <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-400">
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-800 rounded-full"></div> Current</span>
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-200 rounded-full border border-slate-300"></div> Done</span>
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-amber-400 rounded-full"></div> Flag</span>
                        </div>
                        <button onClick={exitQuiz} className="w-full py-3 border border-rose-100 bg-rose-50 text-rose-600 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-rose-100 transition-colors">Abort Session</button>
                    </div>
                </aside>
            </>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Score Card) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
        <div className="h-full bg-slate-100 flex items-center justify-center p-4 overflow-y-auto custom-scrollbar">
            <div className="bg-white max-w-2xl w-full rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500 relative">
                <div className="bg-slate-900 p-10 text-center text-white relative overflow-hidden">
                    {percentage >= 80 && (<div className="absolute inset-0 pointer-events-none opacity-20 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMiIgY3k9IjIiIHI9IjIiIGZpbGw9IiNmZmYiLz48L3N2Zz4=')]"></div>)}
                    <div className="relative z-10">
                        <div className="w-16 h-16 bg-white/10 rounded-2xl mx-auto mb-4 flex items-center justify-center backdrop-blur-md border border-white/10">
                            {percentage >= 70 ? <Trophy size={32} className="text-emerald-400" /> : <AlertTriangle size={32} className="text-rose-400" />}
                        </div>
                        <h2 className="text-3xl font-display font-bold mb-2">Examination Report</h2>
                        <p className="text-slate-400 uppercase tracking-widest text-xs font-bold">Session ID: OT-{Date.now().toString().slice(-6)}</p>
                    </div>
                </div>

                <div className="p-8 md:p-12 space-y-10 text-center">
                    <div className="flex justify-center items-center gap-12">
                        <div className="text-center"><span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{percentage}%</span><span className="text-xs font-bold uppercase tracking-widest text-slate-400">Final Grade</span></div>
                        <div className="w-px h-20 bg-slate-100"></div>
                        <div className="text-center"><span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{score}</span><span className="text-xs font-bold uppercase tracking-widest text-slate-400">Correct Answers</span></div>
                    </div>

                    <div className={`p-6 rounded-2xl border text-left ${percentage >= 70 ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100'}`}>
                        <h4 className={`font-bold text-sm uppercase tracking-wider mb-2 flex items-center gap-2 ${percentage >= 70 ? 'text-emerald-800' : 'text-rose-800'}`}>{percentage >= 70 ? <CheckCircle2 size={18}/> : <AlertTriangle size={18}/>}{percentage >= 70 ? 'Satisfactory Performance' : 'Academic Warning'}</h4>
                        <p className={`text-sm ${percentage >= 70 ? 'text-emerald-700' : 'text-rose-700'}`}>{percentage >= 70 ? "You have demonstrated competency in the selected modules. Maintain current study habits." : "Performance falls below the departmental threshold. We recommend reviewing flagged topics in the Atlas immediately."}</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {hasMistakes ? (
                            <button onClick={retryIncorrectOnly} className="py-4 rounded-xl border-2 border-rose-100 bg-rose-50 text-rose-700 font-bold uppercase text-xs tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2"><RotateCcw size={16} /> Retry Mistakes</button>
                        ) : (
                            <button onClick={retrySession} className="py-4 rounded-xl border-2 border-slate-100 bg-slate-50 text-slate-700 font-bold uppercase text-xs tracking-widest hover:bg-slate-100 transition-all flex items-center justify-center gap-2"><RotateCcw size={16} /> Retake Exam</button>
                        )}
                        <button onClick={() => { setView('review'); if(toggleHeader) toggleHeader(false); }} className="py-4 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-bold uppercase text-xs tracking-widest hover:border-slate-400 transition-all flex items-center justify-center gap-2"><FileText size={16} /> Audit Answers</button>
                    </div>

                    <button onClick={() => saveAndExit(false)} className="w-full py-5 bg-slate-900 text-white rounded-xl font-bold uppercase text-xs tracking-widest hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl">Conclude Session & Return to Dashboard</button>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW (Audit Mode) ---
  if (view === 'review') {
    return (
        <div className="h-full bg-slate-50 flex flex-col">
            <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                <h2 className="font-bold text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2"><FileText size={16} /> Audit Log</h2>
                <button onClick={() => setView('results')} className="text-xs font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900">Return to Score</button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 space-y-6">
                <div className="max-w-4xl mx-auto space-y-4">
                    {questions.map((q, i) => (
                        <div key={i} className={`bg-white rounded-2xl border p-6 md:p-8 shadow-sm ${q.userAnswer === q.correctOption ? 'border-emerald-100' : 'border-rose-100'}`}>
                            <div className="flex gap-4">
                                <span className={`text-sm font-mono font-bold pt-1 ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>Q{i+1}</span>
                                <div className="space-y-4 flex-1">
                                    <h3 className="font-medium text-slate-900 leading-snug text-lg" dangerouslySetInnerHTML={{__html: formatQuestionText(q.data.questionText)}} />
                                    {q.data.questionImage && (<div className="p-2 border border-slate-100 bg-slate-50 rounded-xl w-fit"><img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 rounded-lg" alt="ref" /></div>)}
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm mt-4">
                                        <div className={`p-4 rounded-xl border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}><span className="block text-[10px] font-black uppercase opacity-60 mb-1">Your Selection</span><span className="font-bold block" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} /></div>
                                        {q.userAnswer !== q.correctOption && (<div className="p-4 rounded-xl border bg-slate-50 border-slate-200 text-slate-900"><span className="block text-[10px] font-black uppercase opacity-60 mb-1">Correct Answer</span><span className="font-bold block" dangerouslySetInnerHTML={{__html: q.correctOption}} /></div>)}
                                    </div>
                                    {q.data.explanation && (<div className="mt-4 pt-4 border-t border-slate-100"><div className="bg-indigo-50/50 border border-indigo-100 rounded-xl p-4 relative overflow-hidden"><div className="flex justify-between items-start relative z-10"><div className="flex items-center gap-2 mb-2 text-indigo-700"><Info size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Clinical Rationale</span></div><button onClick={() => speak(q.data.explanation || "Explanation", q.id + '-review-expl')} className={`p-1.5 rounded-lg border transition-all ${isSpeaking && speakingId === q.id + '-review-expl' ? 'bg-indigo-200 border-indigo-300 text-indigo-800' : 'bg-white/50 border-indigo-100 text-indigo-400 hover:bg-white hover:text-indigo-600'}`} title="Read Explanation">{isSpeaking && speakingId === q.id + '-review-expl' ? <VolumeX size={14} /> : <Volume2 size={14} />}</button></div><p className="text-sm text-slate-700 leading-relaxed font-medium" dangerouslySetInnerHTML={{__html: q.data.explanation}} /></div></div>)}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

export default Quiz;

/**
 * Utility to process image URLs through an external caching proxy (wsrv.nl).
 * This ensures images load reliably even if the original source is slow or has CORS issues.
 * It also optimizes images to WebP format for faster loading on mobile networks.
 * 
 * @param url - The original source URL of the image
 * @param width - Desired width for optimization (default: 800px)
 * @returns The proxied and optimized image URL
 */
export const cleanImageUrl = (url: string | undefined, width: number = 800): string => {
  if (!url) return '';

  let clean = url;

  // Fix common issue where URLs might be doubled up (e.g. proxy appended twice)
  if (clean.includes('http') && clean.lastIndexOf('http') > 0) {
    clean = clean.substring(clean.lastIndexOf('http'));
  }

  // URL Encode the source to safely pass it as a query parameter
  const encodedUrl = encodeURIComponent(clean);

  // Construct the proxy URL
  // w: width
  // q: quality (80%)
  // output: webp (modern, smaller format)
  // il: interlaced (progressive loading)
  return `https://wsrv.nl/?url=${encodedUrl}&w=${width}&q=80&output=webp&il`;
};

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  ArrowLeft, ArrowRight, Volume2, 
  Shuffle, ImageIcon, Filter, Layers, 
  ArrowLeftRight, AlertTriangle, CheckCircle2, Trophy,
  RotateCcw, Info
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

interface FlashcardsProps {
  data: Question[];
}

const Flashcards: React.FC<FlashcardsProps> = ({ data }) => {
  const [currentIndex, setCurrentIndex] = useState(() => {
    const saved = localStorage.getItem('ot_flashcard_index');
    return saved ? parseInt(saved, 10) : 0;
  });

  const [isShuffled, setIsShuffled] = useState(() => {
    return localStorage.getItem('ot_flashcard_shuffle') === 'true';
  });

  const [isReversed, setIsReversed] = useState(() => {
    return localStorage.getItem('ot_flashcard_reversed') === 'true';
  });

  const [isFlipped, setIsFlipped] = useState(false);

  const [showImagesOnly, setShowImagesOnly] = useState(() => localStorage.getItem('ot_filter_images') === 'true');
  const [showMistakesOnly, setShowMistakesOnly] = useState(() => localStorage.getItem('ot_filter_mistakes') === 'true');
  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
      return JSON.parse(localStorage.getItem('ot_filter_categories') || '[]');
    } catch { return []; }
  });

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Swipe State
  const [touchStart, setTouchStart] = useState<{ x: number; y: number } | null>(null);
  const [touchEnd, setTouchEnd] = useState<{ x: number; y: number } | null>(null);
  const minSwipeDistance = 50;

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const activeData = useMemo(() => {
    let filtered = data;
    if (showMistakesOnly) filtered = filtered.filter(q => mistakesVault.includes(q.id));
    if (showImagesOnly) filtered = filtered.filter(q => q.questionImage || q.answerImage);
    if (selectedCategories.length > 0) filtered = filtered.filter(q => selectedCategories.includes(q.category));

    if (isShuffled) {
        return [...filtered].sort(() => Math.random() - 0.5);
    }
    return filtered;
  }, [data, showImagesOnly, selectedCategories, showMistakesOnly, mistakesVault, isShuffled]);

  useEffect(() => localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault)), [mistakesVault]);
  useEffect(() => localStorage.setItem('ot_flashcard_index', currentIndex.toString()), [currentIndex]);
  useEffect(() => localStorage.setItem('ot_flashcard_shuffle', String(isShuffled)), [isShuffled]);
  useEffect(() => localStorage.setItem('ot_flashcard_reversed', String(isReversed)), [isReversed]);
  useEffect(() => localStorage.setItem('ot_filter_images', String(showImagesOnly)), [showImagesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_mistakes', String(showMistakesOnly)), [showMistakesOnly]);
  useEffect(() => localStorage.setItem('ot_filter_categories', JSON.stringify(selectedCategories)), [selectedCategories]);

  // Keyboard Navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (isFilterOpen) return;

      if (e.key === 'ArrowRight') {
        if (currentIndex < activeData.length - 1) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c + 1), 150);
        }
      } else if (e.key === 'ArrowLeft') {
        if (currentIndex > 0) {
          setIsFlipped(false);
          cancel();
          setTimeout(() => setCurrentIndex(c => c - 1), 150);
        }
      } else if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        setIsFlipped(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, activeData.length, isFilterOpen, cancel]); 

  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently delete all recorded mistakes?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  useEffect(() => {
    if (currentIndex >= activeData.length) {
      setCurrentIndex(0);
    }
  }, [activeData.length]);

  const currentCard = activeData[currentIndex];

  const frontContent = isReversed ? {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  } : {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  };

  const backContent = isReversed ? {
    label: 'Question', text: currentCard?.questionText, image: currentCard?.questionImage, isQuestion: true
  } : {
    label: 'Answer', text: currentCard?.answerText, image: currentCard?.answerImage, isQuestion: false
  };

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex < activeData.length - 1) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c + 1), 150);
    }
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (currentIndex > 0) {
      setIsFlipped(false);
      cancel();
      setTimeout(() => setCurrentIndex(c => c - 1), 150);
    }
  };

  // --- SWIPE HANDLERS ---
  const onTouchStart = (e: React.TouchEvent) => {
    setTouchEnd(null);
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchMove = (e: React.TouchEvent) => {
    setTouchEnd({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const onTouchEnd = () => {
    if (!touchStart || !touchEnd) return;
    const distanceX = touchStart.x - touchEnd.x;
    const distanceY = touchStart.y - touchEnd.y;
    const isLeftSwipe = distanceX > minSwipeDistance;
    const isRightSwipe = distanceX < -minSwipeDistance;

    // Ensure horizontal swipe is dominant to prevent accidental swipes when scrolling vertically
    if (Math.abs(distanceX) > Math.abs(distanceY)) {
      if (isLeftSwipe) {
        handleNext();
      } else if (isRightSwipe) {
        handlePrev();
      }
    }
  };

  const handleSpeak = (e: React.MouseEvent, text: string, suffix: string) => {
    e.stopPropagation();
    if (isSpeaking) cancel(); else speak(text, currentCard.id + suffix);
  };

  const filterOptions: FilterOption[] = [
    { label: 'Smart Review', subLabel: `${mistakesVault.length} Cards`, icon: AlertTriangle, isActive: showMistakesOnly, onClick: () => setShowMistakesOnly(!showMistakesOnly), colorTheme: 'amber' },
    { label: 'Visuals Only', subLabel: 'Diagrams', icon: ImageIcon, isActive: showImagesOnly, onClick: () => setShowImagesOnly(!showImagesOnly), colorTheme: 'indigo' }
  ];

  const getTextSizeClass = (text: string = '') => {
    const len = text.length;
    if (len < 30) return 'text-xl md:text-5xl';
    if (len < 80) return 'text-lg md:text-4xl';
    if (len < 150) return 'text-base md:text-3xl';
    if (len < 300) return 'text-sm md:text-2xl';
    return 'text-xs md:text-xl';
  };

  const formatCardText = (text: string = '') => {
    if (!text) return '';
    return text
      .replace(/^Define the term:\s*/i, '')
      .replace(/^Anatomical term for:\s*/i, '')
      .replace(/^Define:\s*/i, '')
      .replace(/^Identify the\s+/i, '')
      .trim();
  };

  if (!currentCard) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-8 animate-in fade-in zoom-in-95 duration-500">
        <div className={`w-24 h-24 rounded-full flex items-center justify-center shadow-lg border-4 ${showMistakesOnly ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-white text-slate-400 border-slate-100'}`}>
           {showMistakesOnly ? <Trophy size={48} /> : <Layers size={48} />}
        </div>
        <div className="space-y-3 max-w-xs mx-auto">
            <h3 className="text-2xl font-bold text-slate-900 tracking-tight font-display">
                {showMistakesOnly ? "Review Complete" : "No Cards Found"}
            </h3>
            <p className="text-slate-500 font-medium leading-relaxed">
                {showMistakesOnly ? "Excellent work! You've resolved all items in your Smart Review list." : "Try adjusting your filters to see more cards."}
            </p>
        </div>
        <button 
          onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setShowMistakesOnly(false); }}
          className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold uppercase tracking-widest text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"
        >
          Reset Filters
        </button>
      </div>
    );
  }

  const frontDisplayText = formatCardText(frontContent.text);
  const backDisplayText = formatCardText(backContent.text);

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto w-full relative">
      {/* Top Controls */}
      <div className="flex justify-between items-center px-4 md:px-6 py-2 md:py-6 shrink-0">
        <div className="flex items-center gap-3 md:gap-4">
           <button 
             onClick={() => setIsFilterOpen(true)}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center ${selectedCategories.length > 0 || showImagesOnly || showMistakesOnly ? 'border-rose-200 bg-rose-50 text-rose-700' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
           >
             <Filter className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>

           <div className="flex flex-col">
              <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-0.5 flex items-center gap-2">
                 {showMistakesOnly && <AlertTriangle size={10} className="text-amber-500" />} {showMistakesOnly ? 'Smart Review' : 'Study Deck'}
              </span>
              <span className="text-base md:text-lg font-black text-slate-900 font-display flex items-baseline gap-1">
                 {currentIndex + 1} 
                 <span className="text-xs md:text-sm font-bold text-slate-300">/ {activeData.length}</span>
              </span>
           </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={() => { setIsReversed(!isReversed); setIsFlipped(false); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 ${isReversed ? 'border-emerald-500 text-emerald-600 bg-emerald-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Reverse Sides"
           >
             <ArrowLeftRight className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
           <button 
             onClick={() => { setIsShuffled(!isShuffled); setCurrentIndex(0); }}
             className={`w-10 h-10 md:w-12 md:h-12 rounded-2xl border transition-all flex items-center justify-center hover:bg-slate-50 ${isShuffled ? 'border-purple-500 text-purple-600 bg-purple-50' : 'bg-white border-slate-200 text-slate-400'}`}
             title="Shuffle Deck"
           >
             <Shuffle className="w-4 h-4 md:w-[18px] md:h-[18px]" strokeWidth={2} />
           </button>
        </div>
      </div>

      {/* Card Container */}
      <div className="flex-1 px-4 md:px-8 pb-2 flex flex-col justify-center min-h-0 relative perspective-1000">
        <div 
          className="relative w-full h-full max-h-[700px] cursor-pointer select-none"
          onClick={() => setIsFlipped(!isFlipped)}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
        >
          <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* FRONT FACE */}
            <div className="absolute inset-0 backface-hidden bg-white rounded-[2rem] md:rounded-[2.5rem] shadow-card hover:shadow-card-hover border border-slate-100 p-6 md:p-12 flex flex-col items-center text-center group">
               <div className="w-full flex justify-between items-start mb-2 md:mb-6 shrink-0">
                   <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-slate-300">
                     {frontContent.label}
                   </span>
                   {showMistakesOnly && (
