import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertTriangle, Check, Volume2, RotateCcw,
  Monitor, Trophy, VolumeX, Flame, HeartPulse, Info
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

// --- IMPROVED AUDIO ENGINE ---
const audioCtxRef: { current: AudioContext | null } = { current: null };

const playFeedbackSound = (type: 'correct' | 'wrong' | 'complete') => {
    if (typeof window === 'undefined') return;

    if (!audioCtxRef.current) {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContext) {
            audioCtxRef.current = new AudioContext();
        }
    }

    const ctx = audioCtxRef.current;
    if (!ctx) return;

    if (ctx.state === 'suspended') {
        ctx.resume().catch(() => {});
    }

    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'correct') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now); 
        osc.frequency.exponentialRampToValueAtTime(50, now + 0.5); 
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
        osc.start(now);
        osc.stop(now + 0.5);
    } 
    else if (type === 'wrong') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(150, now);
        osc.frequency.linearRampToValueAtTime(100, now + 0.15);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
    } 
    else if (type === 'complete') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.setValueAtTime(554, now + 0.1);
        osc.frequency.setValueAtTime(659, now + 0.2);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.6);
        osc.start(now);
        osc.stop(now + 0.6);
    }
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => {
  return text.replace(/^(Option|Part)\s+/i, '').trim();
};

const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader, isEmbedded = false, enableConfiguration = false, onExit }) => {
  const savedState = useMemo(() => {
    if (isEmbedded) return null;
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, [isEmbedded]);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(
    savedState?.view || (isEmbedded && !enableConfiguration ? 'playing' : 'setup')
  );

  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);
  const [streak, setStreak] = useState(0);

  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(
    (isEmbedded && !enableConfiguration) ? 'practice' : (savedState?.mode || 'exam')
  );

  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(!isEmbedded); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Helper to prepare questions
  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length > 0 ? [...q.options] : [q.answerText];
      if (finalOptions.length < 2) {
         finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not shown"];
      }
      finalOptions.sort(() => Math.random() - 0.5);
      return {
        id: q.id, 
        data: q,
        options: finalOptions,
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  // Embedded Initialization
  useEffect(() => {
    // Only auto-start if we are embedded AND configuration is NOT enabled.
    // If configuration IS enabled, we let the user pick in the Setup view.
    if (isEmbedded && !enableConfiguration && questions.length === 0 && data.length > 0) {
        let pool = [...data];
        // Shuffle for embedded practice
        pool.sort(() => Math.random() - 0.5);
        const prepared = prepareQuestions(pool);
        setQuestions(prepared);
        setTimeLeft(prepared.length * 60);
        setView('playing');
        setMode('practice');
        if (toggleHeader) toggleHeader(false);
    } else if (isEmbedded && enableConfiguration && questions.length === 0 && data.length > 0) {
        // Just ensure header is hidden if needed, but stay in setup
        if (toggleHeader) toggleHeader(false);
    }
  }, [isEmbedded, enableConfiguration, data, questions.length, toggleHeader]);

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (!isEmbedded) {
        if (view === 'playing' || view === 'results' || view === 'review') {
        localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({
            view, questions, currentQIndex, timeLeft, mode
        }));
        } else {
        localStorage.removeItem('OT_QUIZ_SESSION_V5');
        }
    }
  }, [view, questions, currentQIndex, timeLeft, mode, isEmbedded]);

  useEffect(() => {
    if (!isEmbedded && toggleHeader) {
        if (view === 'playing' || view === 'review') {
            toggleHeader(false);
        } else {
            toggleHeader(true);
        }
    }
  }, [view, toggleHeader, isEmbedded]);

  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024 || isEmbedded) {
            setIsSidebarOpen(false);
        } else {
            setIsSidebarOpen(true);
        }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, [isEmbedded]);

  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) {
        handleFinish();
        return;
      }
      timer = setInterval(() => {
        setTimeLeft((prev) => prev - 1);
      }, 1000);
    }
    return () => {
      if (timer) clearInterval(timer);
    };
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    if (questionRef.current) {
        questionRef.current.scrollTop = 0;
    }
  }, [currentQIndex, view]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (view !== 'playing') return;
      if (e.key === 'ArrowLeft') {
        if (currentQIndex > 0) {
            e.preventDefault();
            setCurrentQIndex(prev => prev - 1);
            setImgError(false);
        }
      } else if (e.key === 'ArrowRight') {
        if (currentQIndex < questions.length - 1) {
            e.preventDefault();
            setCurrentQIndex(prev => prev + 1);
            setImgError(false);
        }
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [view, currentQIndex, questions.length]);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const startSession = () => {
    let pool = data;
    if (mode === 'mistakes') pool = pool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) pool = pool.filter(q => q.questionImage || q.answerImage);

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    if (isShuffle) pool = [...pool].sort(() => Math.random() - 0.5);

    const actualCount = Math.min(pool.length, questionCount);
    const finalPool = pool.slice(0, actualCount);
    const preparedQuestions = prepareQuestions(finalPool);

    if (typeof window !== 'undefined' && (window.AudioContext || (window as any).webkitAudioContext)) {
        if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioCtxRef.current.resume();
    }

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    if(toggleHeader) toggleHeader(false);
  };

  const handleFinish = () => {
    cancel();
    playFeedbackSound('complete');
    setView('results');
  };

  const saveAndExit = (resolveCorrect: boolean) => {
    const wrongIds = questions.filter(q => q.userAnswer !== q.correctOption).map(q => q.id);
    const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
        let next = [...prev];
        if (wrongIds.length > 0) next = [...next, ...wrongIds];
        if (resolveCorrect) next = next.filter(id => !correctIds.includes(id));
        return Array.from(new Set(next));
    });

    if (isEmbedded && onExit) {
        onExit();
    } else {
        localStorage.removeItem('OT_QUIZ_SESSION_V5');
        setView('setup');
        if(toggleHeader) toggleHeader(true);
    }
  };

  const retrySession = () => {
    const resetQuestions = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
    const reshuffled = [...resetQuestions].sort(() => Math.random() - 0.5);
    setQuestions(reshuffled);
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(reshuffled.length * 60);
    setView('playing');
    if(toggleHeader) toggleHeader(false);
  };

  const retryIncorrectOnly = () => {
    const wrongQuestions = questions
        .filter(q => q.userAnswer !== q.correctOption)
        .map(q => ({...q, userAnswer: null, isFlagged: false}));

    if (wrongQuestions.length === 0) return;

    setQuestions(wrongQuestions.sort(() => Math.random() - 0.5));
    setCurrentQIndex(0);
    setStreak(0);
    setTimeLeft(wrongQuestions.length * 60);
    setView('playing');
    if(toggleHeader) toggleHeader(false);
  };

  const exitQuiz = () => {
    if (confirm("End current exam session? Progress will be lost.")) {
      cancel();
      if (isEmbedded && onExit) {
          onExit();
      } else {
          localStorage.removeItem('OT_QUIZ_SESSION_V5');
          setView('setup');
          if(toggleHeader) toggleHeader(true);
      }
    }
  };

  const filterOptions: FilterOption[] = [
    { label: 'Diagrams Only', subLabel: 'Visual Mode', icon: ImageIcon, isActive: showDiagramsOnly, onClick: () => setShowDiagramsOnly(!showDiagramsOnly), colorTheme: 'indigo' }
  ];

  // --- VIEW: SETUP ---
  if (view === 'setup') {
    let filteredPool = data;
    if (mode === 'mistakes') filteredPool = filteredPool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) filteredPool = filteredPool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) filteredPool = filteredPool.filter(q => q.questionImage || q.answerImage);
    const maxQuestions = filteredPool.length;
    if (questionCount > maxQuestions && maxQuestions > 0) setQuestionCount(maxQuestions);

    return (
      <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar relative">
          <div className="min-h-full flex flex-col items-center justify-center p-4 pb-32 md:pb-10">
             <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-200/50 overflow-hidden animate-in zoom-in-95 duration-500 relative">
                {isEmbedded && (
                    <button onClick={onExit} className="absolute top-4 right-4 text-white hover:bg-white/10 p-2 rounded-full z-20"><X size={20}/></button>
                )}
                <div className="bg-slate-900 p-8 md:p-10 text-white relative overflow-hidden">
                    <div className="absolute top-[-20%] right-[-10%] opacity-10"><Monitor size={200} /></div>
                    <h2 className="text-2xl md:text-3xl font-display font-bold tracking-tight mb-2">Exam Configuration</h2>
                    <p className="text-slate-400 text-sm font-medium">Occupational Therapy Department</p>
                </div>
                <div className="p-6 md:p-10 space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {[
                        { id: 'exam', label: 'University Exam', sub: 'Timed • No Hints', icon: Clock, color: 'rose' },
                        { id: 'practice', label: 'Study Mode', sub: 'Interactive Feedback', icon: Zap, color: 'blue' },
                        { id: 'mistakes', label: 'Error Vault', sub: `${mistakesVault.length} items`, icon: AlertTriangle, color: 'amber' }
                    ].map((m) => (
                        <button key={m.id} onClick={() => setMode(m.id as any)} className={`p-5 rounded-2xl border-2 transition-all text-left flex flex-col gap-3 group relative overflow-hidden ${mode === m.id ? `border-${m.color}-500 bg-${m.color}-50 text-${m.color}-900` : 'border-slate-100 hover:border-slate-300 text-slate-500 hover:bg-slate-50'}`}>
                            <div className={`p-2.5 rounded-xl w-fit ${mode === m.id ? `bg-${m.color}-200 text-${m.color}-700` : 'bg-slate-100 group-hover:bg-slate-200'}`}><m.icon size={20} /></div>
                            <div><span className="block font-bold text-sm">{m.label}</span><span className="text-[10px] font-bold uppercase opacity-60 tracking-wider">{m.sub}</span></div>
                        </button>
                    ))}
                    </div>
                    <div className="space-y-6 border-t border-slate-100 pt-6">
                        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                            {/* Hide Category Selector if embedded, because the content is fixed to the Atlas image context */}
                            {!isEmbedded && (
                                <button onClick={() => setIsBankModalOpen(true)} className={`flex-1 w-full p-4 rounded-xl border-2 flex items-center justify-between transition-all ${selectedCategories.length > 0 ? 'border-slate-800 bg-slate-800 text-white' : 'border-slate-200 hover:border-slate-300 text-slate-600 hover:bg-slate-50'}`}>
                                    <div className="flex items-center gap-3"><List size={18} /><div className="text-left"><span className="block text-[10px] font-black uppercase tracking-widest opacity-70">Content Source</span><span className="block text-sm font-bold truncate max-w-[200px]">{selectedCategories.length === 0 ? "All Chapters (Comprehensive)" : `${selectedCategories.length} Modules Selected`}</span></div></div><ChevronRight size={16} />
                                </button>
                            )}
                            <div className="flex-1 w-full space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-200">
                                <div className="flex justify-between text-xs font-bold text-slate-500 uppercase tracking-widest px-1"><span>Question Limit</span><span className="text-slate-900">{questionCount} / {maxQuestions}</span></div>
                                <input type="range" min="1" max={maxQuestions || 1} value={questionCount} disabled={maxQuestions === 0} onChange={(e) => setQuestionCount(Number(e.target.value))} className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900"/>
                            </div>
                        </div>
                    </div>
                    <button onClick={startSession} disabled={maxQuestions === 0} className="w-full py-5 bg-slate-900 hover:bg-rose-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl hover:shadow-2xl transition-all hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"><span>Start Examination</span><ChevronRight size={18} /></button>
                </div>
             </div>
          </div>
          <FilterModal isOpen={isBankModalOpen} onClose={() => setIsBankModalOpen(false)} categories={categories} selectedCategories={selectedCategories} onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} onClearAll={() => { setSelectedCategories([]); setShowDiagramsOnly(false); }} mainOptions={filterOptions} title="Curriculum Selection" />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing' && currentQ) {
    return (
      <div className={`h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900 ${isEmbedded ? 'rounded-none' : ''}`}>

        {/* Top Information Bar */}
        <header className="h-14 md:h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-white text-rose-600 border border-rose-100 rounded-lg flex items-center justify-center shadow-sm">
                    <HeartPulse size={18} className="text-rose-600 md:w-5 md:h-5" />
                </div>
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Anatomy & Physiology</h1>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{isPracticeMode ? 'Formative Assessment' : 'Summative Exam'}</p>
                </div>
                <div className="md:hidden">
                    <span className="text-xs font-bold text-slate-900">Q{currentQIndex + 1}/{questions.length}</span>
                </div>
            </div>

            <div className="flex items-center gap-3 md:gap-6">
                {mode === 'exam' ? (
                    <div className={`flex items-center gap-1.5 md:gap-2 px-3 md:px-4 py-1.5 md:py-2 rounded-lg font-mono font-bold text-sm md:text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-50 text-slate-700 border-slate-200'}`}>
                        <Clock size={16} className="md:w-[18px] md:h-[18px]" /> {formatTime(timeLeft)}
                    </div>
                ) : (
                    <div className="flex gap-2">
                        <span className="px-2 md:px-3 py-1 md:py-1.5 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-lg text-[10px] md:text-xs font-bold flex items-center gap-1"><CheckCircle2 size={12} className="md:w-3.5 md:h-3.5" /> {questions.filter(q => q.userAnswer === q.correctOption).length}</span>
                        <span className="px-2 md:px-3 py-1 md:py-1.5 bg-rose-50 text-rose-700 border border-rose-200 rounded-lg text-[10px] md:text-xs font-bold flex items-center gap-1"><X size={12} className="md:w-3.5 md:h-3.5" /> {questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</span>
                    </div>
                )}

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg transition-colors lg:hidden shadow-sm">
                    <LayoutGrid size={18} className="text-slate-600" />
                </button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden relative">

            {/* Main Question Paper */}
            <main className="flex-1 flex flex-col relative min-w-0">
                {/* Progress Strip */}
                <div className="h-1 bg-slate-200 w-full">
                    <div 
                        className="h-full bg-rose-500 transition-all duration-300" 
                        style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }}
                    />
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white min-h-[500px] shadow-sm border border-slate-200 rounded-2xl overflow-hidden pb-8">

                        {/* Question Header */}
                        <div className="bg-slate-50/80 border-b border-slate-100 p-4 md:p-6 flex justify-between items-start">
                            <div className="flex flex-col gap-1.5 pr-4">
                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest hidden md:block">Question {currentQIndex + 1} of {questions.length}</span>
                                <span className="text-[10px] md:text-xs font-bold text-slate-600 bg-white border border-slate-200 px-3 py-1 rounded-md w-fit max-w-[200px] md:max-w-full truncate">{currentQ.data.category}</span>
                            </div>
                            <div className="flex gap-2 shrink-0">
                                <button onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged; return c; })} className={`p-2 md:p-2.5 rounded-lg border transition-all ${currentQ.isFlagged ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`} title="Mark for Review"><Flag size={16} className="md:w-[18px] md:h-[18px]" fill={currentQ.isFlagged ? "currentColor" : "none"} /></button>
                                <button onClick={() => speak(currentQ.data.questionText, currentQ.id)} className={`p-2 md:p-2.5 rounded-lg border transition-all ${isSpeaking && speakingId === currentQ.id ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white text-slate-400 border-slate-200 hover:border-slate-300'}`}>{isSpeaking && speakingId === currentQ.id ? <VolumeX size={16} className="md:w-[18px] md:h-[18px]" /> : <Volume2 size={16} className="md:w-[18px] md:h-[18px]" />}</button>
                            </div>
                        </div>

                        <div className="p-4 md:p-12 space-y-6 md:space-y-8">
                            {/* Stem */}
                            <h2 className="text-lg md:text-2xl font-display font-medium text-slate-900 leading-relaxed text-balance">
                                <span dangerouslySetInnerHTML={{ __html: formatQuestionText(currentQ.data.questionText) }} />
                            </h2>

                            {/* Image */}
                            {currentQ.data.questionImage && !imgError && (
                                <div className="border border-slate-100 rounded-xl p-2 md:p-4 bg-slate-50 flex justify-center">
                                    <img src={cleanImageUrl(currentQ.data.questionImage)} alt="Clinical Figure" className="max-h-[30vh] md:max-h-[40vh] w-auto object-contain rounded-lg shadow-sm" onError={() => setImgError(true)} />
                                </div>
                            )}

                            {/* Options */}
                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const isCorrect = isPracticeMode && currentQ.userAnswer && opt === currentQ.correctOption;
                                    const isWrong = isPracticeMode && currentQ.userAnswer && isSelected && opt !== currentQ.correctOption;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;

                                    let containerStyle = "border-slate-200 hover:border-slate-300 hover:bg-slate-50 cursor-pointer";
                                    let circleStyle = "border-slate-300 text-slate-500 bg-white";

                                    if (showAnswer) {
                                        if (isCorrect) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/50 cursor-default ring-1 ring-emerald-500 animate-in pulse";
                                            circleStyle = "bg-emerald-500 border-emerald-500 text-white";
                                        } else if (isWrong) {
                                            containerStyle = "border-rose-500 bg-rose-50/50 cursor-default ring-1 ring-rose-500 animate-in shake";
                                            circleStyle = "bg-rose-500 border-rose-500 text-white";
                                        } else if (opt === currentQ.correctOption) {
                                            containerStyle = "border-emerald-500 bg-emerald-50/20 cursor-default"; 
                                            circleStyle = "border-emerald-500 text-emerald-600 bg-emerald-50";
                                        } else {
                                            containerStyle = "border-slate-100 text-slate-400 cursor-default opacity-60";
                                        }
                                    } else if (isSelected) {
                                        containerStyle = "border-slate-900 bg-slate-50 shadow-md ring-1 ring-slate-900";
                                        circleStyle = "bg-slate-900 border-slate-900 text-white";
                                    }

                                    return (
                                        <div key={i} onClick={() => {
                                            if (showAnswer) return;
                                            const correct = opt === currentQ.correctOption;
                                            if (isPracticeMode) {
                                                if (correct) { playFeedbackSound('correct'); setStreak(s => s + 1); } 
                                                else { playFeedbackSound('wrong'); setStreak(0); }
                                            }
                                            setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; });
                                        }} className={`group relative flex items-center gap-3 md:gap-4 p-3 md:p-4 rounded-xl border-2 transition-all duration-200 ${containerStyle}`}>
                                            <div className={`w-7 h-7 md:w-8 md:h-8 rounded-lg border-2 flex items-center justify-center text-xs md:text-sm font-bold shrink-0 transition-colors ${circleStyle}`}>
                                                {showAnswer && isCorrect ? <Check size={14} className="md:w-4 md:h-4" /> : showAnswer && isWrong ? <X size={14} className="md:w-4 md:h-4" /> : letter}
                                            </div>
                                            <div className="flex-1 text-sm md:text-base font-medium leading-relaxed" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Explanation (Practice Mode) */}
                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-4 md:p-6 rounded-xl border text-sm leading-relaxed animate-in fade-in slide-in-from-top-2 shadow-sm relative ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-slate-50 border-slate-200 text-slate-800'}`}>
                                    <div className="flex justify-between items-start mb-2">
                                        <h4 className="font-bold uppercase tracking-widest text-xs opacity-70 flex items-center gap-2">
                                            {currentQ.userAnswer === currentQ.correctOption ? <CheckCircle2 size={16} /> : <AlertTriangle size={16} />}
                                            {currentQ.userAnswer === currentQ.correctOption ? 'Correct Analysis' : 'Clinical Correction'}
                                        </h4>
                                        <button onClick={() => speak(currentQ.data.explanation || "No additional clinical notes available.", currentQ.id + '-expl')} className={`p-1.5 rounded-lg border transition-all ${isSpeaking && speakingId === currentQ.id + '-expl' ? 'bg-white border-current text-current' : 'bg-transparent border-transparent hover:bg-white/50'}`} title="Read Explanation">{isSpeaking && speakingId === currentQ.id + '-expl' ? <VolumeX size={14} /> : <Volume2 size={14} />}</button>
                                    </div>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "No additional clinical notes available." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer Controls */}
                <div className="bg-white border-t border-slate-200 p-4 md:px-8 flex justify-between items-center shadow-[0_-4px_20px_-5px_rgba(0,0,0,0.05)] z-20">
                    <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="flex items-center gap-2 px-4 md:px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest text-slate-600 hover:bg-slate-50 disabled:opacity-30 disabled:hover:bg-transparent transition-all"><ChevronLeft size={16} /> <span className="hidden md:inline">Previous</span></button>
                    <button onClick={() => { if (currentQIndex === questions.length - 1) { handleFinish(); } else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} className="flex items-center gap-2 px-6 md:px-8 py-3 rounded-xl font-bold text-xs uppercase tracking-widest bg-slate-900 text-white hover:bg-rose-600 shadow-lg shadow-slate-200 hover:shadow-rose-100 transition-all hover:-translate-y-0.5 active:translate-y-0">{currentQIndex === questions.length - 1 ? 'Submit Exam' : 'Next'} {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}</button>
                </div>
            </main>

            {/* Sidebar Overlay (Mobile) & Fixed Sidebar (Desktop) */}
            <>
                {/* Backdrop for mobile */}
                {isSidebarOpen && (
                    <div 
                        className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-40 lg:hidden animate-in fade-in"
                        onClick={() => setIsSidebarOpen(false)}
                    />
                )}

                <aside className={`fixed inset-y-0 right-0 z-50 w-[85vw] md:w-80 bg-white shadow-2xl transform transition-transform duration-300 lg:relative lg:translate-x-0 lg:shadow-none lg:z-auto lg:border-l lg:border-slate-200 flex flex-col ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                    <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-slate-50/50">
                        <h3 className="font-black text-xs uppercase tracking-widest text-slate-500">Question Palette</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 p-2 hover:bg-slate-200 rounded-full"><X size={20} /></button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 custom-scrollbar bg-slate-50/30">
                        <div className="grid grid-cols-5 gap-2.5">
                            {questions.map((q, i) => {
                                let style = "bg-white border-slate-200 text-slate-500 hover:border-slate-300 shadow-sm";
                                if (currentQIndex === i) style = "bg-slate-800 border-slate-800 text-white ring-2 ring-slate-200 shadow-md transform scale-105 z-10";
                                else if (q.isFlagged) style = "bg-amber-50 border-amber-400 text-amber-700";
                                else if (q.userAnswer) style = "bg-slate-100 border-slate-300 text-slate-900 font-bold";
                                return (<button key={i} onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} className={`aspect-square rounded-lg flex items-center justify-center text-xs font-medium border-2 transition-all relative group ${style}`}>{i + 1}{q.isFlagged && <div className="absolute top-0.5 right-0.5 w-2 h-2 bg-amber-500 rounded-full border border-white"></div>}</button>)
                            })}
                        </div>
                    </div>

                    <div className="p-6 border-t border-slate-200 bg-white space-y-4 pb-safe">
                        <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest text-slate-400">
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-800 rounded-full"></div> Current</span>
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-slate-200 rounded-full border border-slate-300"></div> Done</span>
                            <span className="flex items-center gap-2"><div className="w-2 h-2 bg-amber-400 rounded-full"></div> Flag</span>
                        </div>
                        <button onClick={exitQuiz} className="w-full py-3 border border-rose-100 bg-rose-50 text-rose-600 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-rose-100 transition-colors">Abort Session</button>
                    </div>
                </aside>
            </>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Score Card) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);
    const hasMistakes = questions.some(q => q.userAnswer !== q.correctOption);

    return (
        <div className="h-full bg-slate-100 flex items-center justify-center p-4 overflow-y-auto custom-scrollbar">
            <div className="bg-white max-w-2xl w-full rounded-[2rem] shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-500 relative">
                <div className="bg-slate-900 p-10 text-center text-white relative overflow-hidden">
                    {percentage >= 80 && (<div className="absolute inset-0 pointer-events-none opacity-20 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMiIgY3k9IjIiIHI9IjIiIGZpbGw9IiNmZmYiLz48L3N2Zz4=')]"></div>)}
                    <div className="relative z-10">
                        <div className="w-16 h-16 bg-white/10 rounded-2xl mx-auto mb-4 flex items-center justify-center backdrop-blur-md border border-white/10">
                            {percentage >= 70 ? <Trophy size={32} className="text-emerald-400" /> : <AlertTriangle size={32} className="text-rose-400" />}
                        </div>
                        <h2 className="text-3xl font-display font-bold mb-2">Examination Report</h2>
                        <p className="text-slate-400 uppercase tracking-widest text-xs font-bold">Session ID: OT-{Date.now().toString().slice(-6)}</p>
                    </div>
                </div>

                <div className="p-8 md:p-12 space-y-10 text-center">
                    <div className="flex justify-center items-center gap-12">
                        <div className="text-center"><span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{percentage}%</span><span className="text-xs font-bold uppercase tracking-widest text-slate-400">Final Grade</span></div>
                        <div className="w-px h-20 bg-slate-100"></div>
                        <div className="text-center"><span className="block text-6xl font-black text-slate-900 mb-2 tracking-tighter">{score}</span><span className="text-xs font-bold uppercase tracking-widest text-slate-400">Correct Answers</span></div>
                    </div>

                    <div className={`p-6 rounded-2xl border text-left ${percentage >= 70 ? 'bg-emerald-50 border-emerald-100' : 'bg-rose-50 border-rose-100'}`}>
                        <h4 className={`font-bold text-sm uppercase tracking-wider mb-2 flex items-center gap-2 ${percentage >= 70 ? 'text-emerald-800' : 'text-rose-800'}`}>{percentage >= 70 ? <CheckCircle2 size={18}/> : <AlertTriangle size={18}/>}{percentage >= 70 ? 'Satisfactory Performance' : 'Academic Warning'}</h4>
                        <p className={`text-sm ${percentage >= 70 ? 'text-emerald-700' : 'text-rose-700'}`}>{percentage >= 70 ? "You have demonstrated competency in the selected modules. Maintain current study habits." : "Performance falls below the departmental threshold. We recommend reviewing flagged topics in the Atlas immediately."}</p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {hasMistakes ? (
                            <button onClick={retryIncorrectOnly} className="py-4 rounded-xl border-2 border-rose-100 bg-rose-50 text-rose-700 font-bold uppercase text-xs tracking-widest hover:bg-rose-100 transition-all flex items-center justify-center gap-2"><RotateCcw size={16} /> Retry Mistakes</button>
                        ) : (
                            <button onClick={retrySession} className="py-4 rounded-xl border-2 border-slate-100 bg-slate-50 text-slate-700 font-bold uppercase text-xs tracking-widest hover:bg-slate-100 transition-all flex items-center justify-center gap-2"><RotateCcw size={16} /> Retake Exam</button>
                        )}
                        <button onClick={() => { setView('review'); if(toggleHeader) toggleHeader(false); }} className="py-4 rounded-xl border-2 border-slate-200 bg-white text-slate-700 font-bold uppercase text-xs tracking-widest hover:border-slate-400 transition-all flex items-center justify-center gap-2"><FileText size={16} /> Audit Answers</button>
                    </div>

                    <button onClick={() => saveAndExit(false)} className="w-full py-5 bg-slate-900 text-white rounded-xl font-bold uppercase text-xs tracking-widest hover:bg-slate-800 transition-all shadow-lg hover:shadow-xl">Conclude Session & Return to Dashboard</button>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW (Audit Mode) ---
  if (view === 'review') {
    return (
        <div className="h-full bg-slate-50 flex flex-col">
            <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                <h2 className="font-bold text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2"><FileText size={16} /> Audit Log</h2>
                <button onClick={() => setView('results')} className="text-xs font-bold uppercase tracking-widest text-slate-500 hover:text-slate-900">Return to Score</button>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 space-y-6">
                <div className="max-w-4xl mx-auto space-y-4">
                    {questions.map((q, i) => (
                        <div key={i} className={`bg-white rounded-2xl border p-6 md:p-8 shadow-sm ${q.userAnswer === q.correctOption ? 'border-emerald-100' : 'border-rose-100'}`}>
                            <div className="flex gap-4">
                                <span className={`text-sm font-mono font-bold pt-1 ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>Q{i+1}</span>
                                <div className="space-y-4 flex-1">
                                    <h3 className="font-medium text-slate-900 leading-snug text-lg" dangerouslySetInnerHTML={{__html: formatQuestionText(q.data.questionText)}} />
                                    {q.data.questionImage && (<div className="p-2 border border-slate-100 bg-slate-50 rounded-xl w-fit"><img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 rounded-lg" alt="ref" /></div>)}
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm mt-4">
                                        <div className={`p-4 rounded-xl border ${q.userAnswer === q.correctOption ? 'bg-emerald-50 border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'}`}><span className="block text-[10px] font-black uppercase opacity-60 mb-1">Your Selection</span><span className="font-bold block" dangerouslySetInnerHTML={{__html: q.userAnswer || "No Answer"}} /></div>
                                        {q.userAnswer !== q.correctOption && (<div className="p-4 rounded-xl border bg-slate-50 border-slate-200 text-slate-900"><span className="block text-[10px] font-black uppercase opacity-60 mb-1">Correct Answer</span><span className="font-bold block" dangerouslySetInnerHTML={{__html: q.correctOption}} /></div>)}
                                    </div>
                                    {q.data.explanation && (<div className="mt-4 pt-4 border-t border-slate-100"><div className="bg-indigo-50/50 border border-indigo-100 rounded-xl p-4 relative overflow-hidden"><div className="flex justify-between items-start relative z-10"><div className="flex items-center gap-2 mb-2 text-indigo-700"><Info size={14} /><span className="text-[10px] font-black uppercase tracking-widest">Clinical Rationale</span></div><button onClick={() => speak(q.data.explanation || "Explanation", q.id + '-review-expl')} className={`p-1.5 rounded-lg border transition-all ${isSpeaking && speakingId === q.id + '-review-expl' ? 'bg-indigo-200 border-indigo-300 text-indigo-800' : 'bg-white/50 border-indigo-100 text-indigo-400 hover:bg-white hover:text-indigo-600'}`} title="Read Explanation">{isSpeaking && speakingId === q.id + '-review-expl' ? <VolumeX size={14} /> : <Volume2 size={14} />}</button></div><p className="text-sm text-slate-700 leading-relaxed font-medium" dangerouslySetInnerHTML={{__html: q.data.explanation}} /></div></div>)}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    )
  }

  return null;
};

export default Quiz;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, BookText, 
  Filter, ArrowUpDown, AlertTriangle, Trash2, FileText, Check, Volume2, VolumeX
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import { useSpeech } from '../hooks/useSpeech';
import { cleanImageUrl } from '../utils';

// Text Cleaning Helper
const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuestionListProps {
  data: Question[];
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data }) => {
  const [search, setSearch] = useState('');
  const [debouncedSearch, setDebouncedSearch] = useState(''); 
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');

  // Unified Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);
  const [showWrittenOnly, setShowWrittenOnly] = useState(false);

  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // Sync with LocalStorage whenever mistakesVault changes
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // PERFORMANCE: Debounce Search Input
  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedSearch(search);
    }, 300); // Wait 300ms after typing stops

    return () => {
      clearTimeout(handler);
    };
  }, [search]);

  const removeMistake = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation(); 
    if (confirm("Resolve this record from the Smart Review list?")) {
      setMistakesVault(prev => prev.filter(item => item !== id));
    }
  };

  const clearAllMistakes = () => {
    if (confirm("WARNING: This will wipe your entire Smart Review history. Are you sure?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false); // Reset view if we were looking at them
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const handleSpeak = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
        cancel();
    } else {
        speak(text, id);
    }
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (showMistakesOnly) {
        result = result.filter(q => mistakesVault.includes(q.id));
    }

    if (showWrittenOnly) {
        result = result.filter(q => {
            const isEssay = q.questionText.startsWith('Define') || 
                            q.questionText.startsWith('List') || 
                            q.questionText.startsWith('Describe') ||
                            q.answerText.length > 80;
            const hasFewOptions = !q.options || q.options.length < 4 || q.options.some(o => o.includes('Option'));
            return isEssay || hasFewOptions;
        });
    }

    if (selectedCategories.length > 0) {
        result = result.filter(q => selectedCategories.includes(q.category || 'General'));
    }

    // Use DEBOUNCED search term for filtering
    if (debouncedSearch.trim()) {
      const term = debouncedSearch.toLowerCase();
      result = result.filter(q => 
        q.questionText.toLowerCase().includes(term) || 
        q.answerText.toLowerCase().includes(term) ||
        (q.explanation || '').toLowerCase().includes(term)
      );
    }

    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));

    return result;
  }, [data, selectedCategories, debouncedSearch, sortOrder, showMistakesOnly, showWrittenOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedSearch, selectedCategories, showMistakesOnly, showWrittenOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  // Filter Configuration
  const filterOptions: FilterOption[] = [
    {
        label: 'Smart Review',
        subLabel: `${mistakesVault.length} Records`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); setShowWrittenOnly(false); },
        colorTheme: 'amber'
    },
    {
        label: 'Concepts Only',
        subLabel: 'Written',
        icon: FileText,
        isActive: showWrittenOnly,
        onClick: () => { setShowWrittenOnly(!showWrittenOnly); setShowMistakesOnly(false); },
        colorTheme: 'indigo'
    }
  ];

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-safe pt-4 md:pt-6">
      {/* Search Header */}
      <div className={`rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-12 mb-6 md:mb-8 text-white relative overflow-hidden shadow-2xl transition-all duration-500 ${showMistakesOnly ? 'bg-amber-500' : showWrittenOnly ? 'bg-indigo-600' : 'bg-rose-600'}`}>
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-4 md:space-y-6">
          <div className="space-y-2">
            <h2 className="text-2xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">
                {showMistakesOnly ? "Review" : showWrittenOnly ? "Concept" : "Global"}<br/><span className="text-white/80 not-italic">{showMistakesOnly ? "Focus List" : showWrittenOnly ? "Library" : "Index"}</span>
            </h2>
            <p className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.4em] opacity-70">
                {showMistakesOnly ? "Diagnostic Repair Mode" : "Integrated Registry v.7.0"}
            </p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder={showMistakesOnly ? "Search review items..." : "Search anatomy terms, chapters or definitions..."}
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
            />
            <Search className="absolute left-4 md:left-5 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-slate-500 transition-colors" size={20} />
          </div>

          <div className="flex flex-wrap gap-2 md:gap-3 items-center">
            {/* Filter Trigger Button */}
            <button 
              onClick={() => setIsFilterOpen(true)}
              className="flex items-center gap-2 px-4 md:px-6 py-2.5 md:py-3 bg-white text-slate-900 rounded-xl font-black uppercase text-[10px] md:text-xs tracking-widest shadow-lg hover:bg-slate-100 transition-all"
            >
              <Filter size={14} /> Filters
              {(selectedCategories.length > 0 || showMistakesOnly || showWrittenOnly) && (
                 <span className="bg-slate-900 text-white px-2 py-0.5 rounded-md">Active</span>
              )}
            </button>

            {showMistakesOnly && mistakesVault.length > 0 && (
                <button 
                    onClick={clearAllMistakes}
                    className="flex items-center gap-2 px-4 py-3 rounded-xl bg-black/20 text-white hover:bg-white hover:text-rose-600 transition-all text-[10px] font-black uppercase"
                >
                    <Trash2 size={14} /> Clear Review
                </button>
            )}

            <div className="flex-1"></div>
            <button 
                onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
                className="p-3 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors text-white"
                title="Sort A-Z"
            >
                <ArrowUpDown size={16} />
            </button>
          </div>
        </div>
      </div>

      {/* Results Grid - content-visibility: auto speeds up rendering */}
      <div className="space-y-4 content-visibility-auto">
        {currentData.length > 0 ? (
          currentData.map((q) => (
            <div key={q.id} className={`bg-white rounded-[2rem] border shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row relative group ${mistakesVault.includes(q.id) ? 'border-amber-200 ring-2 ring-amber-50' : 'border-slate-100'}`}>
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                   <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
                </div>
              )}
              <div className="p-6 md:p-8 flex-1">
                <div className="flex items-center justify-between mb-3 md:mb-4">
                  <span className="text-[9px] font-black uppercase text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200 max-w-[70%] truncate">{q.category}</span>
                  <div className="flex items-center gap-2">
                    {/* Audio Button */}
                    <button 
                        onClick={(e) => handleSpeak(e, `${formatQuestionText(q.questionText)} ... Answer: ${q.answerText}`, q.id)}
                        className={`w-8 h-8 flex items-center justify-center rounded-lg transition-colors ${isSpeaking && speakingId === q.id ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-600'}`}
                        title="Listen"
                    >
                        {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                    </button>

                    {mistakesVault.includes(q.id) && (
                        <div className="flex items-center gap-2">
                            <span className="flex items-center gap-1 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-2 py-1 rounded border border-amber-100"><AlertTriangle size={10} /> Review</span>
                            <button 
                                onClick={(e) => removeMistake(q.id, e)}
                                className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-emerald-50 hover:text-emerald-600 text-slate-400 rounded-lg text-[10px] font-black uppercase tracking-wide transition-colors border border-slate-200"
                                title="Resolve this item"
                            >
                                <Check size={12} />
                            </button>
                        </div>
                    )}
                  </div>
                </div>
                <h3 className="text-lg md:text-xl font-black text-slate-800 leading-tight mb-3" dangerouslySetInnerHTML={{ __html: highlightText(formatQuestionText(q.questionText), debouncedSearch) }} />
                <div className="relative pl-4 md:pl-6 border-l-4 border-slate-200">
                  <p className="text-sm md:text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, debouncedSearch) }} />
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="py-20 text-center bg-slate-50 rounded-[3rem] border-4 border-dashed border-slate-100">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
                {showMistakesOnly ? "Review list is empty. Great job!" : showWrittenOnly ? "No written/concept questions found." : "No matching medical records found"}
            </p>
          </div>
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 mt-8 md:mt-12 mb-32 pb-safe">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-12 md:h-14 px-6 md:px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowWrittenOnly(false); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? clearAllMistakes : undefined}
        mainOptions={filterOptions}
        title="Library Filters"
      />
    </div>
  );
};

export default QuestionList;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Search, Maximize2, Minimize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown, Layers, Scan,
  BrainCircuit, Volume2, VolumeX, PlayCircle, Eye
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import { useSpeech } from '../hooks/useSpeech';
import Quiz from './Quiz';
import { cleanImageUrl } from '../utils';

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  // --- STATE ---
  const [selectedImage, setSelectedImage] = useState<string | null>(() => {
    return localStorage.getItem('ot_atlas_selected_image') || null;
  });

  const [isImageExpanded, setIsImageExpanded] = useState(() => {
    return localStorage.getItem('ot_atlas_image_expanded') === 'true';
  });

  const [isQuizActive, setIsQuizActive] = useState(false);

  const [search, setSearch] = useState(() => {
    return localStorage.getItem('ot_atlas_search') || '';
  });

  const [visibleLimit, setVisibleLimit] = useState(24);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const [showMistakesOnly, setShowMistakesOnly] = useState(() => {
    return localStorage.getItem('ot_atlas_filter_mistakes') === 'true';
  });

  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
        const saved = localStorage.getItem('ot_atlas_filter_categories');
        return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const isMounted = useRef(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // --- EFFECTS ---
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (selectedImage) {
        localStorage.setItem('ot_atlas_selected_image', selectedImage);
        document.body.style.overflow = 'hidden';
    } else {
        localStorage.removeItem('ot_atlas_selected_image');
        document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [selectedImage]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_image_expanded', String(isImageExpanded));
  }, [isImageExpanded]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_search', search);
  }, [search]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_mistakes', String(showMistakesOnly));
  }, [showMistakesOnly]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_categories', JSON.stringify(selectedCategories));
  }, [selectedCategories]);

  useEffect(() => {
    if (!selectedImage || isQuizActive) {
        cancel();
    }
  }, [selectedImage, isQuizActive, cancel]);

  // --- HANDLERS ---
  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently remove all diagrams from your mistakes list?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const handleGridClick = (url: string) => {
    setSelectedImage(url);
    setIsQuizActive(false); // Open detailed list view first
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      title: questions[0].questionText
        .replace(/^In the diagram,?\s*/i, '')
        .replace(/^Identify the\s+/i, '')
        .replace(/^Where is the\s+/i, '')
        .replace(/\??$/i, '')
        .trim(),
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    if (showMistakesOnly) items = items.filter(item => item.hasMistake);
    if (selectedCategories.length > 0) items = items.filter(item => selectedCategories.includes(item.category));

    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term)) ||
            item.related.some(r => r.answerText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  useEffect(() => {
    if (isMounted.current) {
        if (!selectedImage) {
            setIsQuizActive(false);
            setIsImageExpanded(false);
        }
    } else {
        isMounted.current = true;
    }
  }, [selectedImage]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);
  const visibleItems = atlasItems.slice(0, visibleLimit);

  const handleReadAloud = () => {
    if (!activeEntry) return;
    if (isSpeaking && speakingId === 'atlas-summary') {
        cancel();
    } else {
        const points = activeEntry.related.map((p, i) => {
            const label = p.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '').replace(/\??$/i, '');
            return `Point ${i + 1}: ${label}. ${p.answerText}`;
        }).join('. ');

        const fullText = `Structure Breakdown for ${activeEntry.title}. ${points}`;
        speak(fullText, 'atlas-summary');
    }
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50/50 relative">

      {/* Sticky Header Control Bar */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors in diagrams..." : "Search anatomical structures..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
                />
            </div>
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[46px] px-4 md:px-6 rounded-xl border transition-all flex items-center gap-2 font-bold text-xs uppercase tracking-wider ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white ml-1">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Diagnostic Mode Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-3 animate-in slide-in-from-top-2 fade-in">
                <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-2 flex items-center justify-between text-amber-800 shadow-sm">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="text-amber-600" />
                        <span className="text-xs font-bold uppercase tracking-wide">Diagnostic Mode Active</span>
                    </div>
                    <span className="text-[10px] font-bold opacity-70">{atlasItems.length} Diagrams Found</span>
                </div>
            </div>
        )}
      </div>

      {/* Main Content Grid */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar scroll-smooth">
        <div className="max-w-7xl mx-auto pb-32">
            {atlasItems.length > 0 ? (
                <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 content-visibility-auto">
                    {visibleItems.map((item, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => handleGridClick(item.url)}
                            className="group cursor-pointer bg-white rounded-2xl border border-slate-100 shadow-card hover:shadow-card-hover hover:-translate-y-1 transition-all duration-300 flex flex-col overflow-hidden relative"
                        >
                            <div className="aspect-[4/3] bg-slate-50 relative overflow-hidden flex items-center justify-center p-4 border-b border-slate-50">
                                <img 
                                    src={cleanImageUrl(item.url)} 
                                    className="max-w-full max-h-full object-contain transition-transform duration-700 group-hover:scale-105" 
                                    alt="Anatomy Diagram" 
                                    loading="lazy" 
                                />
                                <div className="absolute inset-0 bg-slate-900/0 group-hover:bg-slate-900/5 transition-colors z-10 flex items-center justify-center">
                                    <div className="bg-white/90 backdrop-blur-sm text-slate-900 px-3 py-2 rounded-full font-bold text-[10px] uppercase tracking-widest shadow-lg opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 flex items-center gap-2 transform">
                                        <Eye size={14} className="text-rose-500" /> View Diagram
                                    </div>
                                </div>
                                {item.hasMistake && (
                                    <div className="absolute top-2 right-2 z-20 bg-amber-100 text-amber-600 p-1.5 rounded-lg shadow-sm">
                                        <AlertTriangle size={14} />
                                    </div>
                                )}
                            </div>
                            <div className="p-4 flex-1 flex flex-col justify-between">
                                <div className="space-y-2">
                                    <span className="inline-block px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-widest text-slate-400 border border-slate-100 bg-slate-50 truncate max-w-full">
                                        {item.category.split(':')[0]}
                                    </span>
                                    <h3 className="font-display font-bold text-slate-800 text-sm leading-snug line-clamp-2 group-hover:text-rose-600 transition-colors">
                                        {item.title}
                                    </h3>
                                </div>
                                <div className="mt-4 pt-3 border-t border-slate-50 flex items-center justify-between text-slate-400">
                                    <span className="text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5">
                                        <Layers size={14} className="text-slate-300" /> {item.related.length} Features
                                    </span>
                                    <ChevronRight size={14} className="group-hover:translate-x-1 transition-transform text-rose-300" />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                {visibleLimit < atlasItems.length && (
                    <div className="mt-12 flex justify-center">
                        <button 
                            onClick={() => setVisibleLimit(prev => prev + 24)}
                            className="px-8 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest hover:border-slate-300 hover:bg-slate-50 hover:text-slate-900 transition-all flex items-center gap-2 shadow-sm active:scale-95"
                        >
                            Load More Diagrams <ChevronDown size={14} />
                        </button>
                    </div>
                )}
                </>
            ) : (
                <div className="flex flex-col items-center justify-center py-24 text-center space-y-4 opacity-50">
                    <MapIcon size={48} className="text-slate-300" strokeWidth={1.5} />
                    <p className="font-bold text-slate-400">No Atlas Entries Found</p>
                </div>
            )}
        </div>
      </div>

      {/* DETAILED VIEW MODAL */}
      {activeEntry && (
        <div className="fixed inset-0 z-[300] flex flex-col md:flex-row bg-slate-950/95 backdrop-blur-2xl animate-in fade-in duration-300 overflow-hidden">

          {/* Global Close Button (Hidden in full screen quiz mode) */}
          {!isQuizActive && (
            <button 
                onClick={() => setSelectedImage(null)} 
                className="absolute top-4 right-4 z-[320] p-2.5 bg-black/40 hover:bg-black/60 text-white/90 rounded-full transition-all backdrop-blur-md border border-white/10 group shadow-lg"
            >
                <X size={22} className="group-hover:rotate-90 transition-transform" />
            </button>
          )}

          {/* Left Panel: Image (Hidden in Full Screen Quiz Mode) */}
          {!isQuizActive && (
            <div className={`relative transition-all duration-500 ease-in-out bg-black/20 flex items-center justify-center p-4 md:p-12 overflow-hidden
                ${isImageExpanded ? 'w-full h-full absolute inset-0 z-[310]' : 'h-[38vh] w-full md:h-full md:flex-[1.6]'}
            `}>
                <img 
                    src={cleanImageUrl(activeEntry.url, 1200)} 
                    className={`max-w-full max-h-full object-contain rounded-lg shadow-2xl transition-all duration-500 ${isImageExpanded ? 'scale-100' : 'scale-95'}`}
                    alt="Active Diagram" 
                />

                <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2 z-[315]">
                    <button 
                        onClick={(e) => { e.stopPropagation(); setIsImageExpanded(!isImageExpanded); }}
                        className="bg-black/60 text-white/90 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 border border-white/10 hover:bg-white/20 transition-all shadow-lg"
                    >
                        {isImageExpanded ? <><Minimize2 size={12} /> Minimize</> : <><Maximize2 size={12} /> Expand</>}
                    </button>
                </div>
            </div>
          )}

          {/* Right Panel: Content Sheet or Full Screen Quiz */}
          <div className={`bg-white flex flex-col shadow-2xl relative z-10 transition-all duration-500 
            ${isQuizActive ? 'fixed inset-0 w-full h-full z-[400] rounded-none' : (isImageExpanded ? 'translate-y-full opacity-0 pointer-events-none absolute' : 'flex-1 h-[62vh] md:h-full md:rounded-l-[2.5rem] rounded-t-[2.5rem] md:rounded-tr-none -mt-6 md:mt-0')}
          `}>

            {/* Draggable Handle Indicator for Mobile (Only in sheet mode) */}
            {!isQuizActive && (
                <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mt-3 mb-1 md:hidden shrink-0" />
            )}

            {isQuizActive ? (
                // --- FULL SCREEN EXAM MODE ---
                <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden h-full">
                    <Quiz 
                        key={activeEntry.url + '-quiz'} 
                        data={activeEntry.related} 
                        isEmbedded={true} 
                        enableConfiguration={true} // Enable full setup mode
                        onExit={() => setIsQuizActive(false)} 
                    />
                </div>
            ) : (
                // --- STANDARD INFO LIST (FALLBACK / REVIEW) ---
                <div className="flex flex-col h-full overflow-hidden">
                    <div className="p-6 md:p-8 border-b border-slate-100 bg-white sticky top-0 z-10 shrink-0">
                        <div className="flex items-center gap-2 mb-3">
                            <span className="px-2 py-0.5 bg-rose-50 text-rose-600 rounded text-[9px] font-black uppercase tracking-widest border border-rose-100 truncate max-w-full">
                                {activeEntry.category.split(':')[0]}
                            </span>
                        </div>

                        <div className="flex justify-between items-start gap-4">
                            <h2 className="text-xl md:text-2xl font-display font-bold text-slate-900 leading-tight">
                                Structure Breakdown
                            </h2>
                            <div className="flex gap-2 shrink-0">
                                <button 
                                    onClick={handleReadAloud}
                                    className={`w-10 h-10 flex items-center justify-center rounded-xl border transition-all ${isSpeaking && speakingId === 'atlas-summary' ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-900 hover:border-slate-300'}`}
                                    title="Read Description"
                                >
                                    {isSpeaking && speakingId === 'atlas-summary' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                                </button>
                                <button 
                                    onClick={() => setIsQuizActive(true)}
                                    className="h-10 px-5 bg-slate-900 text-white rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 hover:bg-rose-600 transition-all shadow-lg active:scale-95 hover:shadow-rose-200"
                                >
                                    <BrainCircuit size={16} /> Practice
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 bg-slate-50/50 pb-safe">
                        {activeEntry.related.map((point, pIdx) => {
                            const isMistake = mistakesVault.includes(point.id);
                            return (
                                <div key={pIdx} className={`relative p-5 rounded-2xl bg-white border transition-all duration-300 ${isMistake ? 'border-amber-200 ring-1 ring-amber-100 shadow-sm' : 'border-slate-100 hover:border-slate-200 hover:shadow-sm'}`}>
                                    <div className="flex justify-between items-start mb-2">
                                        <div className="flex items-center gap-3">
                                            <div className={`flex items-center justify-center w-6 h-6 rounded-full text-[10px] font-bold border ${isMistake ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                                {pIdx + 1}
                                            </div>
                                            <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Point of Interest</span>
                                        </div>

                                        {isMistake && (
                                            <button 
                                                onClick={(e) => handleResolveMistake(point.id, e)}
                                                className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-lg text-[10px] font-black uppercase tracking-wider hover:bg-emerald-100 transition-colors border border-emerald-100"
                                            >
                                                <CheckCircle2 size={12} /> Resolve
                                            </button>
                                        )}
                                    </div>

                                    <div className="pl-9 space-y-2">
                                        <p className="text-sm font-bold text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: point.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '') }} />
                                        <div className="relative pl-3 border-l-2 border-rose-200">
                                            <p className="text-sm font-medium text-slate-600" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                                        </div>
                                    </div>
                                </div>
                            );
                        })}

                        <div className="text-center py-8 opacity-50">
                            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">End of Record</span>
                        </div>
                    </div>
                </div>
            )}
          </div>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Filters"
      />
    </div>
  );
};

export default InteractiveAtlas;

import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { 
  Plus, Save, X, Image as ImageIcon, Sparkles, Loader2, 
  Wand2, Globe, CheckCircle2, Layout, Edit3, Eye, 
  RotateCcw, Send, ShieldCheck, Zap, Server, Cpu, Database,
  FileCode, Beaker, Layers, ChevronRight, Binary, Info, Link as LinkIcon,
  ExternalLink, AlertCircle, Terminal, RefreshCw, Activity, Play, Settings,
  Stethoscope, FileText, Microscope, Clipboard
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { cleanImageUrl } from '../utils';

interface QuestionBuilderProps {
  allQuestions: Question[];
  editingId: string | null;
  onSave: (q: Question) => void;
  onCancel: () => void;
  existingCategories: string[];
}

interface GroundingSource {
  title: string;
  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'create' | 'repair'>('create');

  // Repair State
  const [isBatchRepairing, setIsBatchRepairing] = useState(false);
  const [batchStatus, setBatchStatus] = useState({ current: 0, total: 0 });

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  const missingOptionsCount = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4).length;
  }, [allQuestions]);

  const questionsToRepair = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4);
  }, [allQuestions]);

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
        setActiveTab('create');
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Clinical Analysis...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Accessing External Medical Database...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Extracting Anatomical Data...' : 'Synthesizing Clinical Vignette...');

      const prompt = isUrl 
        ? `TASK: Occupational Therapy & Anatomy Education.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE high-quality, board-level anatomy/physiology question relevant to Occupational Therapy.

           REQUIRED OUTPUT FORMAT (JSON):
           {
             "questionText": "Clinical vignette or direct anatomical question",
             "answerText": "Precise correct answer",
             "explanation": "Detailed physiological/anatomical explanation with clinical relevance to OT",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "System or Region (e.g., Upper Extremity, Nervous System)",
             "questionImage": "URL if available"
           }`
        : `TASK: Anatomical Question Synthesis for OT Students.
           INPUT: """${rawInput}"""
           INSTRUCTION: Create a professional anatomy/physiology question from this text. Focus on functional anatomy if possible. Include 3 plausible clinical distractors.

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Formatting Clinical Record...');

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Medical Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON found.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Finalizing Entry...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Error:", error);
      setIsAiLoading(false);
      alert("Analysis interrupted. Please verify the source content.");
    }
  };

  const repairQuestion = async (q: Question) => {
    setIsAiLoading(true);
    setLoadingStep(`Optimizing Record: ${q.id}...`);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `TASK: Generate Medical Distractors.
      QUESTION: "${q.questionText}"
      ANSWER: "${q.answerText}"
      INSTRUCTION: Provide 3 distinct, plausible, but incorrect anatomical/physiological options relevant to OT/Medical boards.

      RETURN JSON: { "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"] }`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["options"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
      onSave(repairedQ);
      setIsAiLoading(false);
      setLoadingStep('');
    } catch (e) {
      setIsAiLoading(false);
      alert("Repair failed.");
    }
  };

  const startBatchRepair = async () => {
    if (questionsToRepair.length === 0) return;
    if (!confirm(`Initialize batch repair for ${questionsToRepair.length} records?`)) return;

    setIsBatchRepairing(true);
    const totalCount = questionsToRepair.length;
    setBatchStatus({ current: 0, total: totalCount });

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let count = 0;
    for (const q of questionsToRepair) {
        count++;
        setBatchStatus({ current: count, total: totalCount });
        setLoadingStep(`Processing: ${count}/${totalCount}`);

        try {
            const prompt = `TASK: Generate Medical Distractors.
            QUESTION: "${q.questionText}"
            ANSWER: "${q.answerText}"
            RETURN JSON: { "options": ["Correct", "Wrong1", "Wrong2", "Wrong3"] }`;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            options: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["options"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");
            const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
            onSave(repairedQ);

            await new Promise(r => setTimeout(r, 500));
        } catch (e) {
            console.error("Batch failure", e);
        }
    }

    setIsBatchRepairing(false);
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8 space-y-8 pb-32 animate-in fade-in duration-700">

      {!showPreview && (
        <div className="flex justify-center mb-6">
          <div className="glass-card p-1.5 rounded-2xl flex gap-1 shadow-sm border border-slate-200/60">
             <button 
              onClick={() => setActiveTab('create')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'create' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <Plus size={16} /> Add Clinical Entry
             </button>
             <button 
              onClick={() => setActiveTab('repair')}
              className={`px-4 md:px-6 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'repair' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}`}
             >
               <RefreshCw size={16} /> Database Repair 
               {missingOptionsCount > 0 && <span className="ml-1 px-1.5 py-0.5 bg-white text-rose-600 text-[9px] rounded-md font-black">{missingOptionsCount}</span>}
             </button>
          </div>
        </div>
      )}

      {/* REPAIR MODE */}
      {activeTab === 'repair' && !showPreview && (
        <div className="max-w-4xl mx-auto space-y-6">
           <div className="glass-card rounded-[2.5rem] p-6 md:p-12 space-y-8 relative overflow-hidden border border-white">
              <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="space-y-2">
