// --- IMPROVED AUDIO ENGINE ---
const audioCtxRef: { current: AudioContext | null } = { current: null };

const playFeedbackSound = (type: 'correct' | 'wrong' | 'complete') => {
    if (typeof window === 'undefined') return;
    if (!audioCtxRef.current) {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (AudioContext) audioCtxRef.current = new AudioContext();
    }
    const ctx = audioCtxRef.current;
    if (!ctx) return;
    if (ctx.state === 'suspended') ctx.resume().catch(() => {});
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);

    if (type === 'correct') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now); 
        osc.frequency.exponentialRampToValueAtTime(50, now + 0.5); 
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.001, now + 0.5);
        osc.start(now);
        osc.stop(now + 0.5);
    } 
    else if (type === 'wrong') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(150, now);
        osc.frequency.linearRampToValueAtTime(100, now + 0.15);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.15);
        osc.start(now);
        osc.stop(now + 0.15);
    } 
    else if (type === 'complete') {
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(440, now);
        osc.frequency.setValueAtTime(554, now + 0.1);
        osc.frequency.setValueAtTime(659, now + 0.2);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0.001, now + 0.6);
        osc.start(now);
        osc.stop(now + 0.6);
    }
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const formatOptionText = (text: string) => text.replace(/^(Option|Part)\s+/i, '').trim();

const formatQuestionText = (text: string) => {
  if (!text) return '';
  return text
    .replace(/^Define the term:\s*/i, '')
    .replace(/^Anatomical term for:\s*/i, '')
    .replace(/^Define:\s*/i, '')
    .replace(/^Identify the\s+/i, '')
    .replace(/^In the diagram,?\s*/i, '')
    .trim();
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader, isEmbedded = false, enableConfiguration = false, onExit, onImageClick }) => {
  const savedState = useMemo(() => {
    if (isEmbedded) return null;
    try {
      const saved = localStorage.getItem('OT_QUIZ_SESSION_V5');
      return saved ? JSON.parse(saved) : null;
    } catch (e) { return null; }
  }, [isEmbedded]);

  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>(
    savedState?.view || (isEmbedded && !enableConfiguration ? 'playing' : 'setup')
  );

  const [questions, setQuestions] = useState<QuizQuestion[]>(savedState?.questions || []);
  const [currentQIndex, setCurrentQIndex] = useState(savedState?.currentQIndex || 0);
  const [timeLeft, setTimeLeft] = useState(savedState?.timeLeft || 0);
  const [imgError, setImgError] = useState(false);

  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>(
    (isEmbedded && !enableConfiguration) ? 'practice' : (savedState?.mode || 'exam')
  );

  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(!isEmbedded); 
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);
  const [isBankModalOpen, setIsBankModalOpen] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const questionRef = useRef<HTMLDivElement>(null);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  const prepareQuestions = (pool: Question[]) => {
    return pool.map(q => {
      let finalOptions = q.options && q.options.length > 0 ? [...q.options] : [q.answerText];
      if (finalOptions.length < 2) {
         finalOptions = [q.answerText, "None of the above", "All of the above", "Structure not shown"];
      }
      finalOptions.sort(() => Math.random() - 0.5);
      return {
        id: q.id, 
        data: q,
        options: finalOptions,
        correctOption: q.answerText, 
        userAnswer: null, 
        isFlagged: false
      } as QuizQuestion;
    });
  };

  useEffect(() => {
    if (isEmbedded && !enableConfiguration && questions.length === 0 && data.length > 0) {
        let pool = [...data].sort(() => Math.random() - 0.5);
        const prepared = prepareQuestions(pool);
        setQuestions(prepared);
        setTimeLeft(prepared.length * 60);
        setView('playing');
        setMode('practice');
        if (toggleHeader) toggleHeader(false);
    } else if (isEmbedded && enableConfiguration && questions.length === 0 && data.length > 0) {
        if (toggleHeader) toggleHeader(false);
    }
  }, [isEmbedded, enableConfiguration, data, questions.length, toggleHeader]);

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (!isEmbedded) {
        if (view === 'playing' || view === 'results' || view === 'review') {
            localStorage.setItem('OT_QUIZ_SESSION_V5', JSON.stringify({ view, questions, currentQIndex, timeLeft, mode }));
        } else {
            localStorage.removeItem('OT_QUIZ_SESSION_V5');
        }
    }
  }, [view, questions, currentQIndex, timeLeft, mode, isEmbedded]);

  useEffect(() => {
    if (!isEmbedded && toggleHeader) {
        toggleHeader(!(view === 'playing' || view === 'review'));
    }
  }, [view, toggleHeader, isEmbedded]);

  useEffect(() => {
    const handleResize = () => {
        if (window.innerWidth < 1024 || isEmbedded) setIsSidebarOpen(false);
        else setIsSidebarOpen(true);
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, [isEmbedded]);

  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam') {
      if (timeLeft <= 0) { handleFinish(); return; }
      timer = setInterval(() => setTimeLeft((prev) => prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  useEffect(() => {
    cancel(); 
    if (questionRef.current) questionRef.current.scrollTop = 0;
  }, [currentQIndex, view]);

  const startSession = () => {
    let pool = data;
    if (mode === 'mistakes') pool = pool.filter(q => mistakesVault.includes(q.id));
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showDiagramsOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    if (pool.length === 0) { alert("No questions found."); return; }
    if (isShuffle) pool = [...pool].sort(() => Math.random() - 0.5);
    const prepared = prepareQuestions(pool.slice(0, Math.min(pool.length, questionCount)));
    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if(toggleHeader) toggleHeader(false);
  };

  const handleFinish = () => {
    cancel();
    playFeedbackSound('complete');
    setView('results');
  };

  const currentQ = questions[currentQIndex];
  const isPracticeMode = mode === 'practice' || mode === 'mistakes';

  if (view === 'playing' && currentQ) {
    return (
      <div className={`h-full flex flex-col bg-[#f1f5f9] font-sans text-slate-900 ${isEmbedded ? 'rounded-none' : ''}`}>
        <header className="h-14 md:h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shadow-sm shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <HeartPulse size={18} className="text-rose-600 md:w-5 md:h-5" />
                <div className="hidden md:block">
                    <h1 className="text-sm font-bold text-slate-900 leading-tight">Exam Portal</h1>
                </div>
                <div className="md:hidden">
                    <span className="text-xs font-bold text-slate-900">Q{currentQIndex + 1}/{questions.length}</span>
                </div>
            </div>
            <div className="flex items-center gap-3 md:gap-6">
                {mode === 'exam' && (
                    <div className={`px-3 py-1.5 rounded-lg font-mono font-bold text-sm md:text-lg border ${timeLeft < 60 ? 'bg-rose-50 text-rose-600 border-rose-200 animate-pulse' : 'bg-slate-50 text-slate-700 border-slate-200'}`}>
                        <Clock size={16} className="inline mr-1" /> {formatTime(timeLeft)}
                    </div>
                )}
                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-white border border-slate-200 lg:hidden rounded-lg"><LayoutGrid size={18} /></button>
            </div>
        </header>

        <div className="flex-1 flex overflow-hidden relative">
            <main className="flex-1 flex flex-col relative min-w-0">
                <div className="h-1 bg-slate-200 w-full">
                    <div className="h-full bg-rose-500" style={{ width: `${((currentQIndex + 1) / questions.length) * 100}%` }} />
                </div>
                <div className="flex-1 overflow-y-auto p-4 md:p-8" ref={questionRef}>
                    <div className="max-w-4xl mx-auto bg-white shadow-sm border border-slate-200 rounded-2xl overflow-hidden pb-8">
                        <div className="bg-slate-50/80 p-4 md:p-6 flex justify-between items-start border-b border-slate-100">
                            <span className="text-[10px] md:text-xs font-bold text-slate-600 bg-white border border-slate-200 px-3 py-1 rounded-md">{currentQ.data.category}</span>
                            <div className="flex gap-2">
                                <button onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].isFlagged = !c[currentQIndex].isFlagged; return c; })} className={`p-2 rounded-lg border ${currentQ.isFlagged ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-white text-slate-400 border-slate-200'}`}><Flag size={16} /></button>
                                <button onClick={() => speak(currentQ.data.questionText, currentQ.id)} className="p-2 bg-white border border-slate-200 rounded-lg text-slate-400">{isSpeaking && speakingId === currentQ.id ? <VolumeX size={16} /> : <Volume2 size={16} />}</button>
                            </div>
                        </div>

                        <div className="p-4 md:p-12 space-y-6">
                            <h2 className="text-lg md:text-2xl font-display font-medium text-slate-900 leading-relaxed" dangerouslySetInnerHTML={{ __html: formatQuestionText(currentQ.data.questionText) }} />

                            {currentQ.data.questionImage && !imgError && (
                                <div 
                                    className="border border-slate-100 rounded-xl p-2 md:p-4 bg-slate-50 flex justify-center relative group cursor-zoom-in"
                                    onClick={() => onImageClick?.(currentQ.data.questionImage!)}
                                >
                                    <img src={cleanImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] w-auto object-contain rounded-lg" onError={() => setImgError(true)} />
                                    <div className="absolute bottom-4 right-4 p-2 bg-black/50 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity">
                                        <Search size={16} />
                                    </div>
                                </div>
                            )}

                            <div className="space-y-3">
                                {currentQ.options.map((opt, i) => {
                                    const letter = String.fromCharCode(65 + i);
                                    const isSelected = currentQ.userAnswer === opt;
                                    const showAnswer = isPracticeMode && currentQ.userAnswer;
                                    const isCorrect = showAnswer && opt === currentQ.correctOption;
                                    const isWrong = showAnswer && isSelected && opt !== currentQ.correctOption;

                                    return (
                                        <div key={i} onClick={() => {
                                            if (showAnswer) return;
                                            if (isPracticeMode) { if (opt === currentQ.correctOption) playFeedbackSound('correct'); else playFeedbackSound('wrong'); }
                                            setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; });
                                        }} className={`group p-4 rounded-xl border-2 transition-all flex items-center gap-4 ${showAnswer ? (isCorrect ? 'border-emerald-500 bg-emerald-50' : isWrong ? 'border-rose-500 bg-rose-50' : 'border-slate-100 opacity-60') : (isSelected ? 'border-slate-900 bg-slate-50' : 'border-slate-200 cursor-pointer hover:bg-slate-50')}`}>
                                            <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center font-bold ${showAnswer ? (isCorrect ? 'bg-emerald-500 text-white' : isWrong ? 'bg-rose-500 text-white' : 'bg-slate-100') : (isSelected ? 'bg-slate-900 text-white' : 'bg-white')}`}>
                                                {showAnswer && isCorrect ? <Check size={16} /> : showAnswer && isWrong ? <X size={16} /> : letter}
                                            </div>
                                            <div className="flex-1 text-sm md:text-base font-medium" dangerouslySetInnerHTML={{ __html: formatOptionText(opt) }} />
                                        </div>
                                    );
                                })}
                            </div>

                            {isPracticeMode && currentQ.userAnswer && (
                                <div className={`mt-6 p-6 rounded-xl border text-sm animate-in slide-in-from-top-2 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-100' : 'bg-slate-50 border-slate-200'}`}>
                                    <h4 className="font-bold uppercase tracking-widest text-[10px] mb-2">Rationale</h4>
                                    <p dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Detailed clinical analysis completed." }} />
                                </div>
                            )}
                        </div>
                    </div>
                </div>
                <div className="bg-white border-t border-slate-200 p-4 md:px-8 flex justify-between items-center z-20">
                    <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="flex items-center gap-2 px-6 py-3 rounded-xl font-bold text-xs uppercase tracking-widest text-slate-600 disabled:opacity-30"><ChevronLeft size={16} /> Previous</button>
                    <button onClick={() => { if (currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(c => c + 1); setImgError(false); } }} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-rose-600 transition-all">{currentQIndex === questions.length - 1 ? 'Submit' : 'Next'} {currentQIndex !== questions.length - 1 && <ChevronRight size={16} />}</button>
                </div>
            </main>

            {isSidebarOpen && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-40 lg:hidden" onClick={() => setIsSidebarOpen(false)} />
            )}
            <aside className={`fixed inset-y-0 right-0 z-50 w-72 bg-white shadow-2xl lg:relative lg:translate-x-0 lg:shadow-none flex flex-col transition-transform ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                <div className="p-5 border-b border-slate-200 font-black text-xs uppercase tracking-widest">Question Palette</div>
                <div className="flex-1 overflow-y-auto p-5 grid grid-cols-5 gap-2 bg-slate-50/30">
                    {questions.map((q, i) => (
                        <button key={i} onClick={() => { setCurrentQIndex(i); if(window.innerWidth < 1024) setIsSidebarOpen(false); }} className={`aspect-square rounded-lg border-2 text-xs font-bold transition-all ${currentQIndex === i ? 'bg-slate-800 border-slate-800 text-white scale-105' : q.userAnswer ? 'bg-slate-100 border-slate-300' : 'bg-white border-slate-200'}`}>{i + 1}</button>
                    ))}
                </div>
            </aside>
        </div>
      </div>
    );
  }
  return null;
};

