                                    <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center font-black text-xs ${showAnswer ? (isCorrect ? 'bg-teal-500 text-white' : isWrong ? 'bg-rose-500 text-white' : 'bg-slate-50') : (isSelected ? 'bg-slate-900 text-white' : 'bg-slate-50 text-slate-400')}`}>
                                        {showAnswer && isCorrect ? <Check size={16} /> : showAnswer && isWrong ? <X size={16} /> : letter}
