            <button onClick={() => currentQIndex === questions.length - 1 ? handleFinish() : setCurrentQIndex(c => c + 1)} className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all flex items-center gap-2">
                {currentQIndex === questions.length - 1 ? 'Submit' : 'Next'} <ChevronRight size={16}/>
            </button>
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full glass shadow-premium relative z-10 p-6 flex flex-col">
                    <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest mb-8">Navigation</h3>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start pb-8 custom-scrollbar">
                        {questions.map((q, i) => (
                            <button key={i} onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} className={`aspect-square rounded-xl border-2 flex items-center justify-center text-xs font-black transition-all ${currentQIndex === i ? 'bg-slate-900 border-slate-900 text-white' : q.userAnswer ? 'bg-teal-50 border-teal-100 text-teal-600' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>{i + 1}</button>
                        ))}
                    </div>
                    <button onClick={() => setView('setup')} className="w-full py-4 bg-rose-50 text-rose-600 rounded-xl font-black text-[10px] uppercase tracking-widest border border-rose-100">End Examination</button>
                </div>
            </div>
        )}
      </div>
    );
  }

  // View: RESULTS
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = Math.round((score / questions.length) * 100);
    return (
        <div className="h-full w-full bg-white flex flex-col items-center justify-center p-6 animate-fade-in overflow-y-auto custom-scrollbar">
