                </div>

                <button onClick={() => { localStorage.removeItem('OT_QUIZ_SESSION_V5'); setView('setup'); if(toggleHeader) toggleHeader(true); if(onExit) onExit(); }} className="text-slate-400 font-black uppercase text-[10px] tracking-widest hover:text-rose-600 transition-colors">Return to Dashboard</button>
            </div>
        </div>
    );
  }

  return null;
};

