                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // View: RESULTS
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = Math.round((score / questions.length) * 100);
    return (
        <div className="h-full w-full bg-slate-50 flex flex-col items-center justify-center p-6 overflow-y-auto custom-scrollbar">
