  const restartQuiz = () => {
    setView('setup');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  useEffect(() => {
    let timer: any;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && view === 'playing' && mode === 'exam') {
        setView('results');
    }
    return () => clearInterval(timer);
