                    className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
                >
                    Start Examination <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => setSelectedCategories([])}
            mainOptions={[]}
            title="Select Exam Chapters"
          />
      </div>
    );
  }

  // View: PLAYING
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isStudy = mode === 'study' || mode === 'vault'; // Vault behaves like study mode
    return (
      <div className="h-full flex flex-col bg-white">
        <header className="h-16 glass border-b border-slate-100 flex items-center justify-between px-6 shrink-0 z-30">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div className="hidden md:block">
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none">Assessment in progress</h1>
                    <p className="text-xs font-bold text-slate-900">Medical Anatomy & Physiology</p>
                </div>
            </div>
            <div className="flex items-center gap-4">
                {mode === 'exam' && (
                    <div className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl font-mono font-bold text-sm border border-rose-100">
                        {formatTime(timeLeft)}
                    </div>
                )}
                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-50 rounded-xl text-slate-400 hover:text-slate-900"><LayoutGrid size={20} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-12" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-8">
                <div className="space-y-6">
                    <span className="px-3 py-1 bg-slate-100 text-[10px] font-black uppercase text-slate-500 rounded-lg border border-slate-200">{currentQ.data.category}</span>
                    <h2 className="text-xl md:text-3xl font-display font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div className="rounded-3xl border border-slate-100 bg-slate-50 p-2 md:p-4 overflow-hidden cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                            <img src={cleanImageUrl(currentQ.data.questionImage)} className="w-full max-h-[40vh] object-contain rounded-2xl" alt="Diagram" />
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;
                            const showAnswer = isStudy && currentQ.userAnswer;
                            const isCorrect = showAnswer && opt === currentQ.correctOption;
                            const isWrong = showAnswer && isSelected && opt !== currentQ.correctOption;

                            return (
                                <button key={i} onClick={() => !showAnswer && setQuestions(prev => { 
                                    const c = [...prev]; 
                                    c[currentQIndex].userAnswer = opt; 
                                    return c; 
                                })} className={`p-5 rounded-2xl border-2 transition-all flex items-center gap-4 text-left group ${showAnswer ? (isCorrect ? 'border-emerald-500 bg-emerald-50 text-emerald-900' : isWrong ? 'border-rose-500 bg-rose-50 text-rose-900' : 'opacity-40 border-slate-100') : (isSelected ? 'border-slate-900 bg-slate-50' : 'border-slate-100 hover:border-slate-200')}`}>
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black text-xs shrink-0 ${showAnswer ? (isCorrect ? 'bg-emerald-500 text-white' : isWrong ? 'bg-rose-500 text-white' : 'bg-slate-100 text-slate-400') : (isSelected ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-400')}`}>
                                        {showAnswer && isCorrect ? <Check size={14} /> : String.fromCharCode(65 + i)}
                                    </div>
                                    <span className="font-bold text-sm md:text-base" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {isStudy && currentQ.userAnswer && (
                    <div className="p-6 md:p-8 bg-slate-950 text-white rounded-[2rem] space-y-4 animate-in slide-in-from-bottom-4 duration-500">
                        <div className="flex items-center gap-3 text-rose-400">
                            <Info size={20} />
                            <h4 className="font-black uppercase text-[10px] tracking-[0.2em]">Scientific Rationale</h4>
                        </div>
                        <p className="text-sm md:text-base text-slate-300 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification confirmed based on clinical standards." }} />
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-6 shrink-0 bg-white z-30">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>
            <button onClick={() => currentQIndex === questions.length - 1 ? handleFinish() : setCurrentQIndex(c => c + 1)} className="px-10 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95">
                {currentQIndex === questions.length - 1 ? 'Finish Exam' : 'Next Question'}
            </button>
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full bg-white shadow-2xl relative z-10 p-8 flex flex-col">
                    <div className="flex justify-between items-center mb-8">
                        <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Navigation</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="p-2 bg-slate-50 rounded-lg text-slate-400"><X size={16} /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start custom-scrollbar">
                        {questions.map((q, i) => (
                            <button key={i} onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} className={`aspect-square rounded-xl border-2 flex items-center justify-center text-xs font-black transition-all ${currentQIndex === i ? 'bg-slate-900 border-slate-900 text-white' : q.userAnswer ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>{i + 1}</button>
                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // View: RESULTS (Updated Premium Design)
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;
    const mistakesCount = questions.length - score;
    const isPass = pct >= 60; // Assuming 60% pass

    return (
        <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar p-4 md:p-6 flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col my-auto shrink-0">

                {/* Result Header */}
                <div className={`p-8 md:p-10 text-center relative overflow-hidden bg-slate-900`}>
                    <div className="relative z-10">
                        <div className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center mb-6 shadow-xl ${isPass ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                            {isPass ? <Trophy size={40} fill="currentColor" /> : <RotateCcw size={40} />}
                        </div>
                        <h2 className="text-4xl md:text-5xl font-black text-white font-display tracking-tight mb-2">{pct}%</h2>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">{isPass ? 'Assessment Passed' : 'Review Required'}</p>
                    </div>

                    {/* Background decoration */}
                    <div className={`absolute top-0 right-0 w-64 h-64 rounded-full blur-[80px] opacity-20 -mr-16 -mt-16 pointer-events-none ${isPass ? 'bg-emerald-400' : 'bg-rose-400'}`}></div>
                </div>

                {/* Stats & Actions */}
                <div className="p-8 md:p-10 space-y-8 bg-white">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 rounded-2xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-2xl font-black text-slate-900">{score}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Correct</span>
                        </div>
                        <div className="p-4 rounded-2xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-2xl font-black text-slate-900">{questions.length}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Total</span>
                        </div>
                    </div>

                    {mistakesCount > 0 && mode === 'exam' && (
                        <div className="flex items-start gap-3 p-4 bg-amber-50 border border-amber-100 rounded-2xl">
                            <Save className="text-amber-500 shrink-0 mt-0.5" size={18} />
                            <div>
                                <h4 className="font-bold text-amber-900 text-xs uppercase tracking-wider mb-1">Smart Vault Active</h4>
                                <p className="text-xs text-amber-700 leading-relaxed">
                                    {mistakesCount} items have been added to your Error Vault for targeted review.
                                </p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-3">
                        <button onClick={() => setView('review')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-[0.15em] shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                            <BarChart3 size={16} /> Review Answers
                        </button>

                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={restartQuiz} className="py-4 bg-white border-2 border-slate-100 rounded-2xl font-black uppercase text-[10px] tracking-widest text-slate-500 hover:border-slate-300 hover:text-slate-900 transition-all">
                                Retake
                            </button>
                            <button onClick={() => { if(onExit) onExit(); restartQuiz(); }} className="py-4 bg-white border-2 border-rose-100 rounded-2xl font-black uppercase text-[10px] tracking-widest text-rose-500 hover:bg-rose-50 transition-all">
                                Exit
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  // View: REVIEW (Analysis)
  if (view === 'review') {
      return (
          <div className="h-full flex flex-col bg-slate-50">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                  <div className="flex items-center gap-4">
                      <button onClick={() => setView('results')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><ArrowLeft size={20}/></button>
                      <h3 className="font-black text-xs uppercase tracking-widest">Clinical Review</h3>
                  </div>
                  <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-3 py-1 rounded-full uppercase">Registry Analysis</span>
              </header>
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                  <div className="max-w-4xl mx-auto space-y-6">
                      {questions.map((q, idx) => {
                          const isCorrect = q.userAnswer === q.correctOption;
                          return (
                              <div key={idx} className={`bg-white rounded-[2rem] border-2 overflow-hidden transition-all shadow-sm ${isCorrect ? 'border-emerald-100' : 'border-rose-100'}`}>
                                  <div className={`p-6 md:p-8 space-y-6`}>
                                      <div className="flex justify-between items-start">
                                          <span className="text-[9px] font-black uppercase text-slate-400">{q.data.category}</span>
                                          {isCorrect ? <CheckCircle2 className="text-emerald-500" size={20} /> : <AlertTriangle className="text-rose-500" size={20} />}
                                      </div>

                                      {q.data.questionImage && (
                                          <div className="mb-4 rounded-xl overflow-hidden border border-slate-100 bg-slate-50 flex items-center justify-center p-2 cursor-zoom-in" onClick={() => onImageClick?.(q.data.questionImage!)}>
                                              <img src={cleanImageUrl(q.data.questionImage)} className="max-h-60 object-contain rounded-lg" alt="Review Diagram" />
                                          </div>
                                      )}

                                      <h4 className="text-base md:text-lg font-bold text-slate-900" dangerouslySetInnerHTML={{ __html: q.data.questionText }} />

                                      <div className="grid gap-2">
                                          <div className={`p-4 rounded-xl text-sm font-bold flex items-center justify-between ${isCorrect ? 'bg-emerald-50 text-emerald-900' : 'bg-rose-50 text-rose-900'}`}>
                                              <span>Your Choice: {q.userAnswer || 'None'}</span>
                                              {!isCorrect && <X size={16} />}
                                          </div>
                                          {!isCorrect && (
                                              <div className="p-4 rounded-xl bg-slate-50 text-slate-900 text-sm font-bold flex items-center justify-between border border-slate-100">
                                                  <span>Correct: {q.correctOption}</span>
                                                  <Check size={16} className="text-emerald-500" />
                                              </div>
                                          )}
                                      </div>

                                      <div className="pt-6 border-t border-slate-50">
                                          <div className="flex items-center gap-2 mb-2 text-slate-400">
                                              <Info size={14} />
                                              <span className="text-[9px] font-black uppercase tracking-widest">Rationale</span>
                                          </div>
                                          <p className="text-sm text-slate-600 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: q.data.explanation || "Clinical data indicates this as the verified anatomical standard." }} />
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
              <footer className="p-6 bg-white border-t border-slate-100">
                  <button onClick={restartQuiz} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, Info, BookOpen, AlertCircle, 
  BarChart3, ArrowLeft, Filter, Save, Flag, ListChecks, HelpCircle
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, toggleHeader, onExit, onImageClick }) => {
  // Added 'summary' to view state for the pre-submission review board
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  // Load mistakes vault
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
      try {
          return JSON.parse(localStorage.getItem('anatomy_mistakes_v5') || '[]');
      } catch { return []; }
  });

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  // Dynamic Pool Calculation
  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakesVault.includes(q.id));
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      return pool;
  }, [mode, mistakesVault, selectedCategories, data]);

  const currentPoolSize = currentPool.length;

  // Adjust limit if it exceeds pool or is too low relative to pool
  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Error Vault is empty or no mistakes match the selected filters! Great job.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    // Prepare Questions
    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); // 1 minute per question default
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  const handleFinish = () => {
    cancel();

    // ERROR VAULT LOGIC:
    // 1. Load current vault
    let currentVault = [...mistakesVault];
    let changesMade = false;

    questions.forEach(q => {
        if (q.userAnswer) {
            const isCorrect = q.userAnswer === q.correctOption;

            if (!isCorrect) {
                // Wrong Answer: Add to vault if not already there
                if (!currentVault.includes(q.id)) {
                    currentVault.push(q.id);
                    changesMade = true;
                }
            } else if (isCorrect && mode === 'vault') {
                // Correct Answer inside Vault Mode: Remove from vault (Remediation)
                if (currentVault.includes(q.id)) {
                    currentVault = currentVault.filter(id => id !== q.id);
                    changesMade = true;
                }
            }
        }
    });

    if (changesMade) {
        localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(currentVault));
        setMistakesVault(currentVault);
    }

    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // View: CONFIGURATION
  if (view === 'config') {
    return (
      <div className="h-full w-full flex items-center justify-center p-4 md:p-6 bg-slate-50/50">
          <div className="w-full max-w-2xl bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[90vh]">
            {/* Header Section */}
            <div className="bg-slate-900 p-8 md:p-10 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-amber-400 text-xs font-bold uppercase tracking-[0.2em] mt-2">Occupational Therapy Department</p>
                </div>
                {/* Subtle background glow */}
                <div className="absolute right-0 top-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="p-8 md:p-10 space-y-8 overflow-y-auto custom-scrollbar">
                {/* Mode Selection Grid */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {/* University Exam */}
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-6 rounded-3xl border-2 text-left transition-all relative overflow-hidden group ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 transition-colors ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={20} />
                        </div>
                        <h3 className={`font-bold text-sm mb-1 ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>University Exam</h3>
                        <p className={`text-[10px] font-black uppercase tracking-wider ${mode === 'exam' ? 'text-rose-400' : 'text-slate-400'}`}>Strict Timing</p>
                    </button>

                    {/* Study Mode */}
                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-6 rounded-3xl border-2 text-left transition-all relative overflow-hidden group ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 transition-colors ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={20} />
                        </div>
                        <h3 className={`font-bold text-sm mb-1 ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study Mode</h3>
                        <p className={`text-[10px] font-black uppercase tracking-wider ${mode === 'study' ? 'text-indigo-400' : 'text-slate-400'}`}>Instant Feedback</p>
                    </button>

                    {/* Error Vault */}
                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-6 rounded-3xl border-2 text-left transition-all relative overflow-hidden group ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 transition-colors ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={20} />
                        </div>
                        <h3 className={`font-bold text-sm mb-1 ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Error Vault</h3>
                        <p className={`text-[10px] font-black uppercase tracking-wider ${mode === 'vault' ? 'text-amber-400' : 'text-slate-400'}`}>{mistakesVault.length} Items</p>
                    </button>
                </div>

                {/* Configuration Row */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Source Selection - Interactive Filter */}
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className={`p-4 rounded-2xl border flex items-center justify-between transition-all group text-left ${mode === 'vault' ? 'bg-slate-50 border-slate-200' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-rose-200 hover:shadow-md'}`}
                    >
                        <div className="flex items-center gap-3 w-full overflow-hidden">
                            <div className={`p-2 rounded-lg border transition-colors bg-white border-slate-200 text-slate-400 group-hover:text-rose-500`}><BookOpen size={16}/></div>
                            <div className="flex flex-col min-w-0">
                                <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Content Source</span>
                                <span className="font-bold text-xs text-slate-700 truncate">
                                    {selectedCategories.length === 0 ? 'All Chapters (Comprehensive)' : `${selectedCategories.length} Chapters Selected`}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className="text-slate-400 group-hover:translate-x-1 transition-transform shrink-0" />
                    </button>

                    {/* Limit Slider - Open System */}
                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 space-y-4">
                         <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Question Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit} / {currentPoolSize}</span>
                         </div>
                         <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                         />
                    </div>
                </div>

                {/* Start Button */}
                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 hover:-translate-y-1 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3"
                >
                    Start Examination <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => setSelectedCategories([])}
            mainOptions={[]}
            title="Select Exam Chapters"
          />
      </div>
    );
  }

  // View: PLAYING
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isStudy = mode === 'study' || mode === 'vault'; 
    const showFeedback = isStudy && currentQ.userAnswer; // Only show feedback in study mode if answered

    return (
      <div className="h-full flex flex-col bg-white">
        <header className="h-16 glass border-b border-slate-100 flex items-center justify-between px-6 shrink-0 z-30">
            <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div className="hidden md:block">
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none">
                        {isExam ? 'Official Assessment' : 'Study Session'}
                    </h1>
                    <p className="text-xs font-bold text-slate-900">Medical Anatomy & Physiology</p>
                </div>
            </div>
            <div className="flex items-center gap-3">
                {isExam && (
                    <div className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl font-mono font-bold text-sm border border-rose-100 flex items-center gap-2">
                        <Clock size={16} />
                        {formatTime(timeLeft)}
                    </div>
                )}

                {/* Flag Button */}
                <button 
                    onClick={(e) => toggleFlag(currentQIndex, e)}
                    className={`p-2.5 rounded-xl border transition-all ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-600' : 'bg-white border-slate-200 text-slate-400 hover:border-slate-300'}`}
                    title="Flag for review"
                >
                    <Flag size={18} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                </button>

                <button onClick={() => setIsSidebarOpen(true)} className="p-2.5 bg-slate-50 rounded-xl text-slate-400 hover:text-slate-900 border border-slate-100"><LayoutGrid size={18} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-12" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-8">
                <div className="space-y-6">
                    <div className="flex justify-between items-start">
                        <span className="px-3 py-1 bg-slate-100 text-[10px] font-black uppercase text-slate-500 rounded-lg border border-slate-200">{currentQ.data.category}</span>
                        {currentQ.isFlagged && <div className="flex items-center gap-1 text-[10px] font-bold text-amber-600 bg-amber-50 px-2 py-1 rounded border border-amber-100"><Flag size={10} fill="currentColor"/> FLAGGED</div>}
                    </div>

                    <h2 className="text-xl md:text-3xl font-display font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div className="rounded-3xl border border-slate-100 bg-slate-50 p-2 md:p-4 overflow-hidden cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                            <img src={cleanImageUrl(currentQ.data.questionImage)} className="w-full max-h-[40vh] object-contain rounded-2xl" alt="Diagram" />
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;

                            // Visual State Logic
                            let containerClass = "border-slate-100 hover:border-slate-200 opacity-100";
                            let iconClass = "bg-slate-100 text-slate-400";
                            let iconContent = String.fromCharCode(65 + i);

                            if (isExam) {
                                // Exam Mode: Blind Selection (Blue/Black only)
                                if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50 ring-1 ring-slate-900";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            } else {
                                // Study Mode: Immediate Feedback
                                if (showFeedback) {
                                    const isCorrect = opt === currentQ.correctOption;
                                    const isWrong = isSelected && !isCorrect;

                                    if (isCorrect) {
                                        containerClass = "border-emerald-500 bg-emerald-50 text-emerald-900";
                                        iconClass = "bg-emerald-500 text-white";
                                        iconContent = <Check size={14} />;
                                    } else if (isWrong) {
                                        containerClass = "border-rose-500 bg-rose-50 text-rose-900";
                                        iconClass = "bg-rose-500 text-white";
                                        iconContent = <X size={14} />;
                                    } else {
                                        containerClass = "opacity-50 border-slate-100";
                                    }
                                } else if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            }

                            return (
                                <button 
                                    key={i} 
                                    onClick={() => {
                                        // In Exam mode: Can change answer anytime. 
                                        // In Study mode: Can only choose if not already answered (locked)
                                        if (isExam || !currentQ.userAnswer) {
                                            setQuestions(prev => { 
                                                const c = [...prev]; 
                                                c[currentQIndex].userAnswer = opt; 
                                                return c; 
                                            });
                                        }
                                    }} 
                                    className={`p-5 rounded-2xl border-2 transition-all flex items-center gap-4 text-left group ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black text-xs shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-bold text-sm md:text-base" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {showFeedback && (
                    <div className="p-6 md:p-8 bg-slate-950 text-white rounded-[2rem] space-y-4 animate-in slide-in-from-bottom-4 duration-500">
                        <div className="flex items-center gap-3 text-rose-400">
                            <Info size={20} />
                            <h4 className="font-black uppercase text-[10px] tracking-[0.2em]">Scientific Rationale</h4>
                        </div>
                        <p className="text-sm md:text-base text-slate-300 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification confirmed based on clinical standards." }} />
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-6 shrink-0 bg-white z-30">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>

            {currentQIndex === questions.length - 1 ? (
                <button 
                    onClick={goToSummary} 
                    className="px-10 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Review & Submit <ListChecks size={16} />
                </button>
            ) : (
                <button 
                    onClick={() => setCurrentQIndex(c => c + 1)} 
                    className="px-10 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95"
                >
                    Next Question
                </button>
            )}
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full bg-white shadow-2xl relative z-10 p-8 flex flex-col">
                    <div className="flex justify-between items-center mb-8">
                        <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Question Map</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="p-2 bg-slate-50 rounded-lg text-slate-400"><X size={16} /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start custom-scrollbar">
                        {questions.map((q, i) => (
                            <button 
                                key={i} 
                                onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} 
                                className={`aspect-square rounded-xl border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                    currentQIndex === i 
                                        ? 'bg-slate-900 border-slate-900 text-white' 
                                        : q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-600' // Blue for answered (neutral in exam)
                                            : 'bg-slate-50 border-slate-100 text-slate-300'
                                }`}
                            >
                                {i + 1}
                                {q.isFlagged && (
                                    <div className="absolute -top-1 -right-1 w-3 h-3 bg-amber-500 rounded-full border-2 border-white"></div>
                                )}
                            </button>
                        ))}
                    </div>
                    <div className="mt-6 pt-6 border-t border-slate-100 grid grid-cols-2 gap-4 text-[10px] font-bold text-slate-500">
                        <div className="flex items-center gap-2"><div className="w-3 h-3 bg-slate-900 rounded"></div> Current</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-3 bg-blue-100 rounded"></div> Answered</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-3 bg-slate-100 rounded"></div> Unanswered</div>
                        <div className="flex items-center gap-2"><div className="w-3 h-3 bg-amber-500 rounded-full"></div> Flagged</div>
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // View: SUMMARY (New University Exam Review Board)
  if (view === 'summary') {
      const answeredCount = questions.filter(q => q.userAnswer).length;
      const flaggedCount = questions.filter(q => q.isFlagged).length;
      const unansweredCount = questions.length - answeredCount;

      return (
          <div className="h-full w-full bg-slate-50 flex flex-col">
              <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-6 md:px-12 shrink-0">
                  <div>
                      <h2 className="text-lg font-black text-slate-900 tracking-tight">Exam Summary</h2>
                      <p className="text-xs text-slate-500 font-bold">Review your answers before final submission</p>
                  </div>
                  {mode === 'exam' && (
                        <div className="px-4 py-2 bg-rose-50 text-rose-600 rounded-xl font-mono font-bold text-sm border border-rose-100 flex items-center gap-2">
                            <Clock size={16} />
                            {formatTime(timeLeft)}
                        </div>
                  )}
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-12">
                  <div className="max-w-5xl mx-auto space-y-8">
                      {/* Stats Overview */}
                      <div className="grid grid-cols-3 gap-4">
                          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-3xl font-black text-blue-600 mb-1">{answeredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Answered</span>
                          </div>
                          <div className={`bg-white p-6 rounded-2xl border shadow-sm flex flex-col items-center ${unansweredCount > 0 ? 'border-rose-100 bg-rose-50' : 'border-slate-100'}`}>
                              <span className={`text-3xl font-black mb-1 ${unansweredCount > 0 ? 'text-rose-600' : 'text-slate-900'}`}>{unansweredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Unanswered</span>
                          </div>
                          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-3xl font-black text-amber-500 mb-1">{flaggedCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Flagged</span>
                          </div>
                      </div>

                      {/* Question Grid */}
                      <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
                          <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6">Question Board</h3>
                          <div className="grid grid-cols-5 md:grid-cols-8 lg:grid-cols-10 gap-3">
                              {questions.map((q, i) => (
                                  <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); setView('playing'); }}
                                    className={`aspect-square rounded-xl border-2 flex flex-col items-center justify-center text-xs font-black transition-all relative hover:scale-105 active:scale-95 ${
                                        q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-700' 
                                            : 'bg-slate-50 border-slate-200 text-slate-400'
                                    }`}
                                  >
                                      {i + 1}
                                      {q.isFlagged && (
                                          <Flag size={12} className="text-amber-500 absolute top-1 right-1" fill="currentColor" />
                                      )}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>

              <footer className="p-6 bg-white border-t border-slate-200 shrink-0 flex justify-between items-center">
                  <button onClick={() => setView('playing')} className="px-8 py-4 rounded-xl border-2 border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:border-slate-300 transition-all">
                      Return to Quiz
                  </button>
                  <button 
                    onClick={handleFinish} 
                    className="px-10 py-4 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-100 flex items-center gap-2"
                  >
                      Final Submission <CheckCircle2 size={16} />
                  </button>
              </footer>
          </div>
      );
  }

  // View: RESULTS (Updated Premium Design)
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;
    const mistakesCount = questions.length - score;
    const isPass = pct >= 60; // Assuming 60% pass

    return (
        <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar p-4 md:p-6 flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col my-auto shrink-0">

                {/* Result Header */}
                <div className={`p-8 md:p-10 text-center relative overflow-hidden bg-slate-900`}>
                    <div className="relative z-10">
                        <div className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center mb-6 shadow-xl ${isPass ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                            {isPass ? <Trophy size={40} fill="currentColor" /> : <RotateCcw size={40} />}
                        </div>
                        <h2 className="text-4xl md:text-5xl font-black text-white font-display tracking-tight mb-2">{pct}%</h2>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">{isPass ? 'Assessment Passed' : 'Review Required'}</p>
                    </div>

                    {/* Background decoration */}
                    <div className={`absolute top-0 right-0 w-64 h-64 rounded-full blur-[80px] opacity-20 -mr-16 -mt-16 pointer-events-none ${isPass ? 'bg-emerald-400' : 'bg-rose-400'}`}></div>
                </div>

                {/* Stats & Actions */}
                <div className="p-8 md:p-10 space-y-8 bg-white">
                    <div className="grid grid-cols-2 gap-4">
                        <div className="p-4 rounded-2xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-2xl font-black text-slate-900">{score}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Correct</span>
                        </div>
                        <div className="p-4 rounded-2xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-2xl font-black text-slate-900">{questions.length}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Total</span>
                        </div>
                    </div>

                    {mistakesCount > 0 && mode === 'exam' && (
                        <div className="flex items-start gap-3 p-4 bg-amber-50 border border-amber-100 rounded-2xl">
                            <Save className="text-amber-500 shrink-0 mt-0.5" size={18} />
                            <div>
                                <h4 className="font-bold text-amber-900 text-xs uppercase tracking-wider mb-1">Smart Vault Active</h4>
                                <p className="text-xs text-amber-700 leading-relaxed">
                                    {mistakesCount} items have been added to your Error Vault for targeted review.
                                </p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-3">
                        <button onClick={() => setView('review')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-[0.15em] shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                            <BarChart3 size={16} /> Review Answers
                        </button>

                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={restartQuiz} className="py-4 bg-white border-2 border-slate-100 rounded-2xl font-black uppercase text-[10px] tracking-widest text-slate-500 hover:border-slate-300 hover:text-slate-900 transition-all">
                                Retake
                            </button>
                            <button onClick={() => { if(onExit) onExit(); restartQuiz(); }} className="py-4 bg-white border-2 border-rose-100 rounded-2xl font-black uppercase text-[10px] tracking-widest text-rose-500 hover:bg-rose-50 transition-all">
                                Exit
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  // View: REVIEW (Analysis)
  if (view === 'review') {
      return (
          <div className="h-full flex flex-col bg-slate-50">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 sticky top-0 z-30">
                  <div className="flex items-center gap-4">
                      <button onClick={() => setView('results')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><ArrowLeft size={20}/></button>
                      <h3 className="font-black text-xs uppercase tracking-widest">Clinical Review</h3>
                  </div>
                  <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-3 py-1 rounded-full uppercase">Registry Analysis</span>
              </header>
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                  <div className="max-w-4xl mx-auto space-y-6">
                      {questions.map((q, idx) => {
                          const isCorrect = q.userAnswer === q.correctOption;
                          return (
                              <div key={idx} className={`bg-white rounded-[2rem] border-2 overflow-hidden transition-all shadow-sm ${isCorrect ? 'border-emerald-100' : 'border-rose-100'}`}>
                                  <div className={`p-6 md:p-8 space-y-6`}>
                                      <div className="flex justify-between items-start">
                                          <span className="text-[9px] font-black uppercase text-slate-400">{q.data.category}</span>
                                          {isCorrect ? <CheckCircle2 className="text-emerald-500" size={20} /> : <AlertTriangle className="text-rose-500" size={20} />}
                                      </div>

                                      {q.data.questionImage && (
                                          <div className="mb-4 rounded-xl overflow-hidden border border-slate-100 bg-slate-50 flex items-center justify-center p-2 cursor-zoom-in" onClick={() => onImageClick?.(q.data.questionImage!)}>
                                              <img src={cleanImageUrl(q.data.questionImage)} className="max-h-60 object-contain rounded-lg" alt="Review Diagram" />
                                          </div>
                                      )}

                                      <h4 className="text-base md:text-lg font-bold text-slate-900" dangerouslySetInnerHTML={{ __html: q.data.questionText }} />

                                      <div className="grid gap-2">
                                          <div className={`p-4 rounded-xl text-sm font-bold flex items-center justify-between ${isCorrect ? 'bg-emerald-50 text-emerald-900' : 'bg-rose-50 text-rose-900'}`}>
                                              <span>Your Choice: {q.userAnswer || 'None'}</span>
                                              {!isCorrect && <X size={16} />}
                                          </div>
                                          {!isCorrect && (
                                              <div className="p-4 rounded-xl bg-slate-50 text-slate-900 text-sm font-bold flex items-center justify-between border border-slate-100">
                                                  <span>Correct: {q.correctOption}</span>
                                                  <Check size={16} className="text-emerald-500" />
                                              </div>
                                          )}
                                      </div>

                                      <div className="pt-6 border-t border-slate-50">
                                          <div className="flex items-center gap-2 mb-2 text-slate-400">
                                              <Info size={14} />
                                              <span className="text-[9px] font-black uppercase tracking-widest">Rationale</span>
                                          </div>
                                          <p className="text-sm text-slate-600 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: q.data.explanation || "Clinical data indicates this as the verified anatomical standard." }} />
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
              <footer className="p-6 bg-white border-t border-slate-100">
                  <button onClick={restartQuiz} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

