import { questions as ch3 } from '../hooks/data_ch3';
import { questions as ch4 } from '../hooks/data_ch4';
import { questions as ch5 } from '../hooks/data_ch5';
import { questions as ch6 } from '../hooks/data_ch6';
import { questions as ch7 } from '../hooks/data_ch7';
import { questions as ch8 } from '../hooks/data_ch8';
import { questions as ch9 } from '../hooks/data_ch9';
import { questions as ch10 } from '../hooks/data_ch10';
import { questions as ch11 } from '../hooks/data_ch11';
import { questions as ch12 } from '../hooks/data_ch12';
import { questions as ch13 } from '../hooks/data_ch13';
import { questions as ch14 } from '../hooks/data_ch14';
import { questions as ch15 } from '../hooks/data_ch15';
import { questions as ch16 } from '../hooks/data_ch16';
import { questions as ch17 } from '../hooks/data_ch17';

import { Trash2, BookOpen, Stethoscope, HeartPulse, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [hasStarted, setHasStarted] = useState(() => {
    return localStorage.getItem('ot_has_started') === 'true';
  });

  // PERSISTENCE: Load last mode or default to Flashcards
  const [currentMode, setCurrentMode] = useState<AppMode>(() => {
    const savedMode = localStorage.getItem('ot_current_mode');
    // Validate saved mode against enum to prevent errors if modes were removed
    if (!Object.values(AppMode).includes(savedMode as AppMode)) {
        return AppMode.FLASHCARDS;
    }
    return (savedMode as AppMode) || AppMode.FLASHCARDS;
  });

  const [isHeaderVisible, setIsHeaderVisible] = useState(true);

  // GLOBAL IMAGE ZOOM STATE
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // SAVE EFFECTS
  useEffect(() => {
    localStorage.setItem('ot_current_mode', currentMode);
  }, [currentMode]);

  useEffect(() => {
    localStorage.setItem('ot_has_started', String(hasStarted));
  }, [hasStarted]);

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  useEffect(() => {
    setIsHeaderVisible(true);
  }, [currentMode]);

  // --- ULTIMATE DATA ENGINE & INTEGRITY SYSTEM ---
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    const rawSources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...ch12, ...ch13, ...ch14, ...ch15, ...ch16, ...ch17,
        ...userVault
    ];

    // Helper to sanitize text (trim, normalize spaces)
    const clean = (str: string | undefined) => str ? str.trim().replace(/\s+/g, ' ') : '';

    // 1. Create Answer Pools for Distractors
    const globalAnswerPool: string[] = [];
    const categoryAnswerPools: Record<string, string[]> = {};

    rawSources.forEach(q => {
        const cat = q.category || 'General';
        if (!categoryAnswerPools[cat]) categoryAnswerPools[cat] = [];

        const cleanAnswer = clean(q.answerText);
        // Add valid short answers to pools to be used as distractors
        if (cleanAnswer && cleanAnswer.length < 100 && !cleanAnswer.toLowerCase().includes('all of the above') && !cleanAnswer.toLowerCase().includes('none of the above')) {
            categoryAnswerPools[cat].push(cleanAnswer);
            globalAnswerPool.push(cleanAnswer);
        }
    });

    // 2. Process Every Question with Integrity Checks
    rawSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            // Sanitize core fields
            const cleanQ = {
                ...q,
                questionText: clean(q.questionText),
                answerText: clean(q.answerText),
                explanation: clean(q.explanation),
                options: (q.options || []).map(clean).filter(Boolean)
            };

            let finalOptions = [...cleanQ.options];
            const answerNorm = cleanQ.answerText.toLowerCase();

            // AUTO-FIX: Generate options if missing or insufficient
            if (finalOptions.length < 2) {
                const cat = q.category || 'General';
                let pool = categoryAnswerPools[cat] || [];

                if (pool.length < 10) pool = [...pool, ...globalAnswerPool];

                // Filter out the actual correct answer from the pool (fuzzy match)
                const validDistractors = pool.filter(a => a.toLowerCase() !== answerNorm);
                const uniqueDistractors = Array.from(new Set(validDistractors));

                const randomDistractors = uniqueDistractors
                    .sort(() => 0.5 - Math.random())
                    .slice(0, 3);

                finalOptions = [cleanQ.answerText, ...randomDistractors];

                // Fallback distractors
                while (finalOptions.length < 4) {
                    const fallbacks = ["None of the above", "All of the above", "Structure not visible", "Not applicable"];
                    for (const fb of fallbacks) {
                        if (!finalOptions.includes(fb) && finalOptions.length < 4) {
                            finalOptions.push(fb);
                        }
                    }
                    if (finalOptions.length < 4) break;
                }

                finalOptions.sort(() => 0.5 - Math.random());
            }

            // INTEGRITY CHECK: Ensure the correct answer is ALWAYS one of the options
            // Use exact match after cleaning
            if (!finalOptions.includes(cleanQ.answerText)) {
                // Remove a random wrong option if we have too many
                if (finalOptions.length >= 4) {
                    finalOptions.pop(); 
                }
                finalOptions.push(cleanQ.answerText);
                finalOptions.sort(() => 0.5 - Math.random());
            }

            // Final Deduplication of options
            finalOptions = Array.from(new Set(finalOptions));

            uniqueQuestions.push({ ...cleanQ, options: finalOptions });
            seenIds.add(cleanQ.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  if (!hasStarted) {
    return (
      <div className="h-[100dvh] w-full bg-slate-50 flex flex-col items-center justify-center p-6 relative overflow-hidden font-sans text-slate-900">
         <div className="absolute inset-0 bg-white"></div>
         <div className="absolute top-0 left-0 right-0 h-[50vh] md:h-[60vh] bg-slate-50 rounded-b-[3rem] md:rounded-b-[4rem] z-0"></div>

         <div className="relative z-10 w-full max-w-md mx-auto flex flex-col items-center text-center space-y-8 md:space-y-10 animate-fade-in">
            <div className="w-24 h-24 md:w-28 md:h-28 bg-white rounded-3xl shadow-xl shadow-slate-200 flex items-center justify-center relative cursor-pointer hover:scale-105 transition-transform duration-500" onClick={() => setHasStarted(true)}>
                <div className="absolute inset-0 bg-gradient-to-br from-rose-50 to-slate-50 rounded-3xl opacity-50"></div>
                <HeartPulse size={48} className="text-rose-500 relative z-10 md:w-14 md:h-14" strokeWidth={1.5} />
            </div>

            <div className="space-y-3">
               <span className="inline-block px-4 py-1.5 rounded-full bg-amber-50 text-amber-600 text-[11px] font-black uppercase tracking-[0.25em] border border-amber-200 shadow-sm">
                  Occupational Therapy
               </span>
               <h1 className="text-4xl md:text-6xl font-black text-slate-900 tracking-tight leading-tight font-display">
                  Anatomy <span className="text-rose-500">&</span><br/>Physiology <span className="text-amber-500">OT</span>
               </h1>
            </div>

            <div className="w-full space-y-6">
                <button 
                  onClick={() => setHasStarted(true)}
                  className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold uppercase tracking-widest text-xs shadow-xl hover:bg-rose-600 hover:shadow-rose-200 transition-all transform active:scale-95 flex items-center justify-center gap-3"
                >
                     <span>Start Clinical Session</span>
                     <ChevronRight size={16} />
                </button>

                <div className="flex justify-center items-center gap-6 md:gap-8 text-slate-300">
                    <div className="flex flex-col items-center gap-1.5">
                        <BookOpen size={18} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">{allQuestions.length} Items</span>
                    </div>
                    <div className="w-px h-8 bg-slate-200"></div>
                    <div className="flex flex-col items-center gap-1.5">
                        <Stethoscope size={18} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Clinical</span>
                    </div>
                </div>
            </div>
         </div>
      </div>
    );
  }

  return (
    <div className="h-[100dvh] w-full flex flex-col font-sans text-slate-900 overflow-hidden bg-slate-50/50">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => setCurrentMode(m)} />
      )}

      {/* Main Content Area - Global Standards Layout (Increased Width) */}
      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isHeaderVisible ? 'pt-0 md:pt-4 md:pb-6 max-w-[1800px] px-0 md:px-6' : 'max-w-full'}`}>

        <div className={`w-full h-full md:rounded-[3rem] overflow-hidden shadow-none md:shadow-2xl md:border border-white/60 bg-white md:bg-white/80 backdrop-blur-3xl relative z-10 transition-all duration-700 flex flex-col ${!isHeaderVisible ? 'rounded-none border-none bg-white' : ''}`}>

            {currentMode === AppMode.FLASHCARDS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Flashcards data={allQuestions} onImageClick={setZoomedImage} />
              </div>
            )}

            {currentMode === AppMode.ATLAS && (
              <div className="w-full h-full animate-fade-in pb-20 md:pb-0 flex-1 flex flex-col">
                <InteractiveAtlas data={allQuestions} onImageClick={setZoomedImage} />
              </div>
            )}

            {currentMode === AppMode.QUIZ && (
              <div className="w-full h-full animate-scale-in pb-20 md:pb-0 flex-1 flex flex-col">
                <Quiz 
                  data={allQuestions} 
                  toggleHeader={setIsHeaderVisible} 
                  onImageClick={setZoomedImage}
                />
              </div>
            )}

            {currentMode === AppMode.LIST && (
              <div className="w-full h-full overflow-y-auto px-4 py-6 custom-scrollbar pb-32 md:pb-6 animate-fade-in flex-1">
                <QuestionList 
                  data={allQuestions}
                  onImageClick={setZoomedImage}
                />
                {userVault.length > 0 && (
                    <div className="flex justify-center p-12 pb-32">
                    <button onClick={() => confirm("Reset user data?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors flex items-center gap-2">
                        <Trash2 size={12} /> Factory Reset User Data
                    </button>
                    </div>
                )}
              </div>
            )}
        </div>
      </main>

      <MobileNavigation 
        currentMode={currentMode} 
        onModeChange={(m) => setCurrentMode(m)}
        isVisible={isHeaderVisible}
